@@ -0,0 +1,138 @@
+codeunit 134602 "ERM Purch. Journal Doc. Amount"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase Journal] [Currency] [Decimal Places]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryJournals: Codeunit "Library - Journals";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+        WrongDecimalErr: Label 'Document Amount should support 3 decimal places', Locked = true;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure DocumentAmountAcceptsThreeDecimalPlacesWithCurrency()
+    var
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GenJournalLine: Record "Gen. Journal Line";
+        PurchaseJournal: TestPage "Purchase Journal";
+        CurrencyCode: Code[10];
+        AmountWith3Decimals: Decimal;
+    begin
+        // [SCENARIO] Document Amount field in Purchase Journal accepts amounts with 3 decimal places when using a currency with 3 decimal places (e.g., TND)
+        // [GIVEN] A currency with 3 decimal places (like TND - Tunisian Dinar)
+        Initialize();
+
+        // [GIVEN] Create a currency with "Amount Decimal Places" = '3:3' and "Amount Rounding Precision" = '0.001'
+        CurrencyCode := CreateCurrencyWithThreeDecimalPlaces();
+
+        // [GIVEN] A Purchase Journal batch
+        CreatePurchaseJournalBatch(GenJournalBatch);
+
+        // [GIVEN] A gen. journal line for a vendor
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::Invoice, GenJournalLine."Account Type"::Vendor,
+            LibraryPurchase.CreateVendorNo(), 0);
+        GenJournalLine.Validate("Currency Code", CurrencyCode);
+        GenJournalLine.Modify(true);
+
+        // [WHEN] Open Purchase Journal page and try to set Document Amount with 3 decimal places (1.234)
+        AmountWith3Decimals := 1.234;
+        Commit();
+        PurchaseJournal.OpenEdit();
+        PurchaseJournal.CurrentJnlBatchName.SetValue(GenJournalBatch.Name);
+        PurchaseJournal.GotoRecord(GenJournalLine);
+
+        // [THEN] The Document Amount field should accept the value with 3 decimal places without error
+        PurchaseJournal.DocumentAmount.SetValue(AmountWith3Decimals);
+
+        // [THEN] Verify that the Document Amount value ends with the expected decimal format
+        Assert.IsTrue(PurchaseJournal.DocumentAmount.Value.Contains('1.234') or
+                      PurchaseJournal.DocumentAmount.Value.Contains('1,234'),
+                      WrongDecimalErr);
+
+        PurchaseJournal.Close();
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure DocumentAmountFieldShowsCorrectDecimalsForCurrencyWith3DecimalPlaces()
+    var
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GenJournalLine: Record "Gen. Journal Line";
+        PurchaseJournal: TestPage "Purchase Journal";
+        CurrencyCode: Code[10];
+    begin
+        // [SCENARIO 388998] Document Amount field in Purchase Journal should display amounts with the correct number of decimal places based on currency
+        Initialize();
+
+        // [GIVEN] Currency with "Amount Decimal Places" = '3:3' (e.g., TND currency)
+        CurrencyCode := CreateCurrencyWithThreeDecimalPlaces();
+
+        // [GIVEN] A Purchase Journal batch with a line
+        CreatePurchaseJournalBatch(GenJournalBatch);
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::Invoice, GenJournalLine."Account Type"::Vendor,
+            LibraryPurchase.CreateVendorNo(), 0);
+        GenJournalLine.Validate("Currency Code", CurrencyCode);
+        GenJournalLine.Modify(true);
+
+        // [WHEN] Open Purchase Journal and view the Document Amount
+        Commit();
+        PurchaseJournal.OpenEdit();
+        PurchaseJournal.CurrentJnlBatchName.SetValue(GenJournalBatch.Name);
+        PurchaseJournal.GotoRecord(GenJournalLine);
+
+        // [THEN] Document Amount field ends with '.000' indicating 3 decimal places
+        Assert.IsTrue(
+            PurchaseJournal.DocumentAmount.Value.EndsWith('.000') or
+            PurchaseJournal.DocumentAmount.Value.EndsWith(',000'),
+            WrongDecimalErr);
+
+        PurchaseJournal.Close();
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"ERM Purch. Journal Doc. Amount");
+
+        if IsInitialized then
+            exit;
+        IsInitialized := true;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"ERM Purch. Journal Doc. Amount");
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"ERM Purch. Journal Doc. Amount");
+    end;
+
+    local procedure CreateCurrencyWithThreeDecimalPlaces(): Code[10]
+    var
+        Currency: Record Currency;
+        CurrencyCode: Code[10];
+    begin
+        // Create a currency similar to TND (Tunisian Dinar) which has 3 decimal places
+        CurrencyCode := LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), 1, 1);
+        Currency.Get(CurrencyCode);
+        Currency.Validate("Amount Decimal Places", '3:3');
+        Currency.Validate("Amount Rounding Precision", 0.001);
+        Currency.Modify(true);
+        exit(CurrencyCode);
+    end;
+
+    local procedure CreatePurchaseJournalBatch(var GenJournalBatch: Record "Gen. Journal Batch")
+    var
+        GenJournalTemplate: Record "Gen. Journal Template";
+    begin
+        LibraryJournals.CreateGenJournalBatch(GenJournalBatch,
+            LibraryJournals.SelectGenJournalTemplate(GenJournalTemplate.Type::Purchases, Page::"Purchase Journal"));
+    end;
+}

diff --git a/App/Apps/W1/Sustainability/test/src/SustainabilityCalcMgtTest.Codeunit.al b/App/Apps/W1/Sustainability/test/src/SustainabilityCalcMgtTest.Codeunit.al
