+codeunit 148185 "Sustainability Calc. Mgt. Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySustainability: Codeunit "Library - Sustainability";
+
+    [Test]
+    procedure GetCollectableGLAmountReturnsAbsoluteValueForNegativeAmount()
+    var
+        SustainAccountCategory: Record "Sustain. Account Category";
+        GLAccount: Record "G/L Account";
+        GLEntry: Record "G/L Entry";
+        SustainabilityCalcMgt: Codeunit "Sustainability Calc. Mgt.";
+        LibraryERM: Codeunit "Library - ERM";
+        CollectedAmount: Decimal;
+        NegativeAmount: Decimal;
+    begin
+        // [SCENARIO] GetCollectableGLAmount should return positive (absolute) value when G/L entries have negative amounts
+        // This ensures Custom Amount and Emissions calculations are always based on positive values
+
+        // [GIVEN] Clean up before testing
+        LibrarySustainability.CleanUpBeforeTesting();
+
+        // [GIVEN] A G/L Account for testing
+        LibraryERM.CreateGLAccount(GLAccount);
+
+        // [GIVEN] A Sustainability Category with Custom calculation foundation and G/L Account Filter
+        SustainAccountCategory.Init();
+        SustainAccountCategory.Validate(Code, 'TESTCAT');
+        SustainAccountCategory.Validate(Description, 'Test Category');
+        SustainAccountCategory.Validate("Emission Scope", Enum::"Emission Scope"::"Scope 3");
+        SustainAccountCategory.Validate("Calculation Foundation", Enum::"Calculation Foundation"::Custom);
+        SustainAccountCategory.Validate("Custom Value", 'TestValue');
+        SustainAccountCategory.Validate(CO2, true);
+        SustainAccountCategory.Validate(CH4, false);
+        SustainAccountCategory.Validate(N2O, false);
+        SustainAccountCategory.Validate("Calculate from General Ledger", true);
+        SustainAccountCategory.Validate("G/L Account Filter", GLAccount."No.");
+        SustainAccountCategory.Insert(true);
+
+        // [GIVEN] A G/L Entry with a negative amount (simulating a credit entry like Net Change of -52,818.18)
+        NegativeAmount := -52818.18;
+        GLEntry.Init();
+        GLEntry."Entry No." := 1;
+        GLEntry."G/L Account No." := GLAccount."No.";
+        GLEntry."Posting Date" := WorkDate();
+        GLEntry.Amount := NegativeAmount;
+        GLEntry.Insert();
+
+        // [WHEN] GetCollectableGLAmount is called
+        CollectedAmount := SustainabilityCalcMgt.GetCollectableGLAmount(SustainAccountCategory, WorkDate(), WorkDate());
+
+        // [THEN] The collected amount should be positive (absolute value)
+        Assert.IsTrue(CollectedAmount > 0, 'Custom Amount from G/L Entries must always be positive');
+        Assert.AreEqual(Abs(NegativeAmount), CollectedAmount, 'Collected amount should be the absolute value of the negative G/L amount');
+
+        // Cleanup
+        GLEntry.Delete();
+    end;
+
+    [Test]
+    procedure GetCollectableGLAmountReturnsPositiveValueForPositiveAmount()
+    var
+        SustainAccountCategory: Record "Sustain. Account Category";
+        GLAccount: Record "G/L Account";
+        GLEntry: Record "G/L Entry";
+        SustainabilityCalcMgt: Codeunit "Sustainability Calc. Mgt.";
+        LibraryERM: Codeunit "Library - ERM";
+        CollectedAmount: Decimal;
+        PositiveAmount: Decimal;
+    begin
+        // [SCENARIO] GetCollectableGLAmount should return positive value when G/L entries already have positive amounts
+
+        // [GIVEN] Clean up before testing
+        LibrarySustainability.CleanUpBeforeTesting();
+
+        // [GIVEN] A G/L Account for testing
+        LibraryERM.CreateGLAccount(GLAccount);
+
+        // [GIVEN] A Sustainability Category with Custom calculation foundation and G/L Account Filter
+        SustainAccountCategory.Init();
+        SustainAccountCategory.Validate(Code, 'TESTCAT2');
+        SustainAccountCategory.Validate(Description, 'Test Category 2');
+        SustainAccountCategory.Validate("Emission Scope", Enum::"Emission Scope"::"Scope 3");
+        SustainAccountCategory.Validate("Calculation Foundation", Enum::"Calculation Foundation"::Custom);
+        SustainAccountCategory.Validate("Custom Value", 'TestValue');
+        SustainAccountCategory.Validate(CO2, true);
+        SustainAccountCategory.Validate(CH4, false);
+        SustainAccountCategory.Validate(N2O, false);
+        SustainAccountCategory.Validate("Calculate from General Ledger", true);
+        SustainAccountCategory.Validate("G/L Account Filter", GLAccount."No.");
+        SustainAccountCategory.Insert(true);
+
+        // [GIVEN] A G/L Entry with a positive amount
+        PositiveAmount := 52818.18;
+        GLEntry.Init();
+        GLEntry."Entry No." := 2;
+        GLEntry."G/L Account No." := GLAccount."No.";
+        GLEntry."Posting Date" := WorkDate();
+        GLEntry.Amount := PositiveAmount;
+        GLEntry.Insert();
+
+        // [WHEN] GetCollectableGLAmount is called
+        CollectedAmount := SustainabilityCalcMgt.GetCollectableGLAmount(SustainAccountCategory, WorkDate(), WorkDate());
+
+        // [THEN] The collected amount should still be positive
+        Assert.IsTrue(CollectedAmount > 0, 'Collected amount should be positive');
+        Assert.AreEqual(PositiveAmount, CollectedAmount, 'Collected amount should equal the positive G/L amount');
+
+        // Cleanup
+        GLEntry.Delete();
+    end;
+}

diff --git a/App/Layers/W1/Tests/ERM/IssuedReminderEmailLinkTest.Codeunit.al b/App/Layers/W1/Tests/ERM/IssuedReminderEmailLinkTest.Codeunit.al
new file mode 100644
