index 00000000..789e78b1
--- /dev/null
+++ b/App/Apps/W1/SubscriptionBilling/Test/Billing/ContractInvoiceDocTotalTest.Codeunit.al
@@ -0,0 +1,220 @@
+namespace Microsoft.SubscriptionBilling;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Sales.Customer;
+using Microsoft.Sales.Document;
+
+codeunit 148161 "Contract Invoice Doc Total Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+    Access = Internal;
+
+    var
+        BillingLine: Record "Billing Line";
+        BillingTemplate: Record "Billing Template";
+        Customer: Record Customer;
+        CustomerContract: Record "Customer Subscription Contract";
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ServiceCommPackageLine: Record "Subscription Package Line";
+        ServiceCommitmentPackage: Record "Subscription Package";
+        ServiceCommitmentTemplate: Record "Sub. Package Line Template";
+        ServiceObject: Record "Subscription Header";
+        Assert: Codeunit Assert;
+        ContractTestLibrary: Codeunit "Contract Test Library";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryRandom: Codeunit "Library - Random";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ExchangeRateSelectionModalPageHandler,MessageHandler')]
+    procedure ContractInvoiceSalesLineShouldNotExcludeFromDocTotal()
+    var
+        SalesInvoice: TestPage "Sales Invoice";
+    begin
+        // [SCENARIO] When a Contract Invoice is generated from Subscription Billing, 
+        // the Sales Invoice lines should NOT be excluded from document total,
+        // so the header amounts are correctly displayed.
+        // This is different from Quote/Order documents where service commitment items 
+        // are excluded from document total.
+        Initialize();
+
+        // [GIVEN] A Service Commitment Item with subscription package
+        CreateServiceCommitmentItemWithPackage();
+
+        // [GIVEN] A Service Object for the customer with the item
+        ContractTestLibrary.CreateCustomerInLCY(Customer);
+        ContractTestLibrary.CreateServiceObjectForItem(ServiceObject, Item, false);
+        ServiceObject.SetHideValidationDialog(true);
+        ServiceObject.Validate("End-User Customer Name", Customer.Name);
+        ServiceObject.Quantity := 1;
+        ServiceObject.Modify(false);
+        InsertServiceCommitmentsFromPackage();
+
+        // [GIVEN] A Customer Contract with the service object
+        ContractTestLibrary.CreateCustomerContractAndCreateContractLinesForItems(CustomerContract, ServiceObject, Customer."No.");
+
+        // [WHEN] Create billing proposal and billing document (Sales Invoice)
+        ContractTestLibrary.CreateBillingProposal(BillingTemplate, Enum::"Service Partner"::Customer);
+        BillingLine.SetRange("Billing Template Code", BillingTemplate.Code);
+        BillingLine.SetRange("Subscription Header No.", ServiceObject."No.");
+        Codeunit.Run(Codeunit::"Create Billing Documents", BillingLine);
+
+        // [THEN] The billing line should reference a Sales Invoice
+        BillingLine.FindFirst();
+        BillingLine.TestField("Document Type", BillingLine."Document Type"::Invoice);
+        BillingLine.TestField("Document No.");
+
+        // [THEN] The Sales Invoice line should NOT have "Exclude from Doc. Total" set to true
+        SalesHeader.Get(SalesHeader."Document Type"::Invoice, BillingLine."Document No.");
+        SalesLine.SetRange("Document Type", SalesHeader."Document Type");
+        SalesLine.SetRange("Document No.", SalesHeader."No.");
+        SalesLine.SetRange(Type, SalesLine.Type::Item);
+        SalesLine.FindFirst();
+        SalesLine.TestField("Line Amount");
+        Assert.AreEqual(false, SalesLine."Exclude from Doc. Total", 'Contract Invoice Sales Line should NOT exclude from document total');
+
+        // [THEN] The Sales Invoice page should show correct total amount
+        SalesInvoice.OpenView();
+        SalesInvoice.GoToRecord(SalesHeader);
+        SalesInvoice.SalesLines."Total Amount Excl. VAT".AssertEquals(SalesLine."Line Amount");
+        SalesInvoice.Close();
+    end;
+
+    [Test]
+    procedure SalesQuoteWithServiceCommitmentItemShouldExcludeFromDocTotal()
+    var
+        SalesQuote: TestPage "Sales Quote";
+    begin
+        // [SCENARIO] When a Sales Quote is created with a Service Commitment Item,
+        // the Sales Quote line SHOULD be excluded from document total.
+        // This confirms the expected behavior for Quote documents hasn't changed.
+        Initialize();
+
+        // [GIVEN] A Service Commitment Item
+        ContractTestLibrary.CreateItemWithServiceCommitmentOption(Item, Enum::"Item Service Commitment Type"::"Service Commitment Item");
+        ContractTestLibrary.UpdateItemUnitCostAndPrice(Item, LibraryRandom.RandDec(1000, 2), LibraryRandom.RandDec(1000, 2), true);
+
+        // [GIVEN] A Sales Quote with the Service Commitment Item
+        LibrarySales.CreateSalesHeader(SalesHeader, Enum::"Sales Document Type"::Quote, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandDec(10, 2));
+
+        // [THEN] The Sales Quote line SHOULD have "Exclude from Doc. Total" set to true
