diff --git a/App/Layers/W1/Tests/VAT/NonDedVATMisc.Codeunit.al b/App/Layers/W1/Tests/VAT/NonDedVATMisc.Codeunit.al
index be592f1e..03e81d5d 100644
--- a/App/Layers/W1/Tests/VAT/NonDedVATMisc.Codeunit.al
+++ b/App/Layers/W1/Tests/VAT/NonDedVATMisc.Codeunit.al
@@ -921,6 +921,71 @@ codeunit 134284 "Non Ded. VAT Misc."
             'Total Cost (LCY) with Non-Deductible VAT amount is not correct in Job Journal Line');
     end;

+    [Test]
+    [Scope('OnPrem')]
+    procedure JobJnlLineWithNonDeductNormalVATFromGenJnlLineWithFCYJob()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        GenJnlLine: Record "Gen. Journal Line";
+        JobJnlLine: Record "Job Journal Line";
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobTransferLine: Codeunit "Job Transfer Line";
+        Currency: Record Currency;
+        Customer: Record Customer;
+        DeductiblePercent: Decimal;
+        ExpectedUnitCostLCY: Decimal;
+        ExpectedTotalCostLCY: Decimal;
+        CurrencyFactor: Decimal;
+    begin
+        // [FEATURE] [Normal VAT] [FCY Job] [UT]
+        // [SCENARIO 581234] Job journal line built from the general journal line (LCY) includes non deductible VAT in "Unit Cost (LCY)" correctly converted when job has a foreign currency
+        Initialize();
+        LibraryNonDeductibleVAT.SetUseForJobCost();
+
+        // [GIVEN] VAT Posting Setup, where "Tax Calculation Type"::"Normal VAT", 'Deductible %' is '60'
+        DeductiblePercent := LibraryRandom.RandInt(90);
+        CreateNonDeductibleVATPostingSetup(VATPostingSetup, "Tax Calculation Type"::"Normal VAT", '', DeductiblePercent);
+
+        // [GIVEN] Currency EUR with exchange rate 7.5 (1 EUR = 7.5 LCY)
+        LibraryERM.CreateCurrency(Currency);
+        CurrencyFactor := LibraryRandom.RandDecInRange(5, 10, 2);
+        LibraryERM.CreateExchangeRate(Currency.Code, WorkDate(), 1 / CurrencyFactor, 1 / CurrencyFactor);
+
+        // [GIVEN] Job with Currency Code = EUR
+        LibrarySales.CreateCustomer(Customer);
+        LibraryJob.CreateJob(Job, Customer."No.");
+        Job.Validate("Currency Code", Currency.Code);
+        Job.Modify(true);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] General journal line in LCY (no currency) where line contains Amount = 100, "Job No." = 'J', "Job Task No." = 'JT', "Job Line Type" = 'Billable'
+        LibraryJob.CreateJobGLJournalLine(GenJnlLine."Job Line Type"::Billable, JobTask, GenJnlLine);
+        GenJnlLine.Validate("Gen. Posting Type", GenJnlLine."Gen. Posting Type"::Purchase);
+        GenJnlLine.Validate("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        GenJnlLine.Validate("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        GenJnlLine.Modify(true);
+
+        // [WHEN] Run FromGenJnlLineToJnlLine
+        JobTransferLine.FromGenJnlLineToJnlLine(GenJnlLine, JobJnlLine);
+
+        // [THEN] JobJnlLine "Unit Cost (LCY)" includes the Non-Deductible VAT Amount converted using the job currency factor
+        // When Gen Jnl Line is in LCY and Job is in FCY, the Non-Ded VAT Amount LCY should be used as-is
+        // The currency factor from LCY to Job FCY is 1 / (1 / CurrencyFactor) = CurrencyFactor
+        // But since the Gen Jnl Line has no currency ("Currency Factor" = 0), 
+        // and Job has a currency ("Job Currency Factor" != 0), the factor is "Job Currency Factor"
+        ExpectedUnitCostLCY := Round((GenJnlLine."VAT Base Amount (LCY)" + Round(GenJnlLine."Non-Deductible VAT Amount" * GenJnlLine.GetGenJnlLineToJobCurrencyFactor())) / GenJnlLine."Job Quantity");
+        ExpectedTotalCostLCY := Round(GenJnlLine."VAT Base Amount (LCY)" + Round(GenJnlLine."Non-Deductible VAT Amount" * GenJnlLine.GetGenJnlLineToJobCurrencyFactor()));
+        Assert.AreEqual(
+            ExpectedUnitCostLCY,
+            Round(JobJnlLine."Unit Cost (LCY)"),
+            'Unit Cost (LCY) with Non-Deductible VAT amount should be correctly converted for FCY Job');
+        Assert.AreEqual(
+            ExpectedTotalCostLCY,
+            Round(JobJnlLine."Total Cost (LCY)"),
+            'Total Cost (LCY) with Non-Deductible VAT amount should be correctly converted for FCY Job');
+    end;
+
