+    [Test]
+    [Scope('OnPrem')]
+    procedure CarryOutActionMsgRespectsActionMessageFilter()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        PurchaseHeader: Record "Purchase Header";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        CarryOutActionMsgPlan: Report "Carry Out Action Msg. - Plan.";
+        PurchOrderChoice: Option " ","Make Purch. Orders","Make Purch. Orders & Print","Copy to Req. Wksh";
+        Quantity: Decimal;
+    begin
+        // [SCENARIO] When filtering Planning Worksheet by Action Message and running Carry Out Action Message, 
+        // only the filtered lines should be processed.
+        Initialize();
+
+        // [GIVEN] Create an item with Order reordering policy and Purchase replenishment system.
+        CreateItem(Item, Item."Reordering Policy"::Order, Item."Replenishment System"::Purchase);
+
+        // [GIVEN] Create a Purchase Order for the item with a date far in the future (will result in Cancel action).
+        Quantity := LibraryRandom.RandIntInRange(5, 10);
+        CreatePurchaseOrder(PurchaseHeader, Item."No.", CalcDate('<+1Y>', WorkDate()), Quantity);
+
+        // [GIVEN] Create a Sales Order for the item with shipment date in the near future (will result in New action).
+        CreateSalesOrder(SalesHeader, SalesLine, Item."No.", Quantity);
+        UpdateShipmentDateOnSalesLine(SalesLine, CalcDate('<+1M>', WorkDate()));
+
+        // [GIVEN] Create a planning worksheet and calculate the regenerative plan for the item.
+        CreateRequisitionWorksheetName(RequisitionWkshName);
+        Item.SetRecFilter();
+        LibraryPlanning.CalcRegenPlanForPlanWkshAndGetLines(
+            RequisitionLine, Item, WorkDate(), CalcDate('<+2Y>', WorkDate()));
+
+        // [GIVEN] Accept Action Message on all requisition lines for the item.
+        AcceptActionMessage(Item."No.");
+
+        // [GIVEN] Verify that we have two lines: one with Action Message = Cancel and one with Action Message = New.
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'Expected to find a Cancel action message line.');
+        
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'Expected to find a New action message line.');
+
+        // [WHEN] Filter by Action Message = Cancel and run Carry Out Action Message.
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        RequisitionLine.FindFirst();
+        
+        Commit();
+        CarryOutActionMsgPlan.SetReqWkshLine(RequisitionLine);
+        CarryOutActionMsgPlan.InitializeRequest(
+            0, PurchOrderChoice::"Make Purch. Orders", 0, 0);
+        CarryOutActionMsgPlan.SetTableView(RequisitionLine);
+        CarryOutActionMsgPlan.SetHideDialog(true);
+        CarryOutActionMsgPlan.UseRequestPage(false);
+        CarryOutActionMsgPlan.RunModal();
+
+        // [THEN] The Cancel line should be processed (deleted from the worksheet).
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        Assert.IsFalse(RequisitionLine.FindFirst(), 'Cancel action message line should have been carried out.');
+
+        // [THEN] The New line should still exist (not processed) because the filter was for Cancel only.
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'New action message line should still exist because it was not filtered.');
+    end;
