+    [Test]
+    [Scope('OnPrem')]
+    procedure NonDedVAT100PctPricesIncludingVATRoundingNonInconsistencyError()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        VATEntry: Record "VAT Entry";
+        Vendor: Record Vendor;
+        GLAccount: Record "G/L Account";
+        DocNo: Code[20];
+    begin
+        // [SCENARIO] Posting purchase invoice with 100% Non-Deductible VAT and "Prices Including VAT" should not throw inconsistency error
+        // [GIVEN] The issue occurs with specific amounts like 14.19 that cause rounding problems
+        Initialize();
+
+        // [GIVEN] Enable "Use For Item Cost" on VAT Setup
+        LibraryNonDeductibleVAT.SetUseForItemCost();
+
+        // [GIVEN] Create VAT Posting Setup with VAT % = 20 and Non-Deductible VAT % = 100
+        LibraryNonDeductibleVAT.CreateVATPostingSetupWithNonDeductibleDetail(VATPostingSetup, 20, 100);
+
+        // [GIVEN] Create a Vendor with "Prices Including VAT" = true
+        Vendor.Get(LibraryPurchase.CreateVendorWithVATBusPostingGroup(VATPostingSetup."VAT Bus. Posting Group"));
+        Vendor.Validate("Prices Including VAT", true);
+        Vendor.Modify(true);
+
+        // [GIVEN] Create a G/L Account with the VAT Product Posting Group
+        LibraryERM.CreateGLAccount(GLAccount);
+        GLAccount.Validate("Gen. Posting Type", GLAccount."Gen. Posting Type"::Purchase);
+        GLAccount.Validate("Gen. Prod. Posting Group", LibraryERM.FindGenProductPostingGroup());
+        GLAccount.Validate("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        GLAccount.Validate("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        GLAccount.Modify(true);
+
+        // [GIVEN] Create a Purchase Invoice for the vendor
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Invoice, Vendor."No.");
+
+        // [GIVEN] Create a Purchase Line with Type = G/L Account, Quantity = 1 and Direct Unit Cost Incl VAT = 14.19
+        // This specific amount causes rounding issues with 100% Non-Deductible VAT and Prices Including VAT
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::"G/L Account", GLAccount."No.", 1);
+        PurchaseLine.Validate("Direct Unit Cost", 14.19);
+        PurchaseLine.Modify(true);
+
+        // [WHEN] Post the Purchase Invoice
+        // Before the fix, this would throw an inconsistency error due to rounding issues
+        // where Base was -0.01 and Amount was 0.01 instead of both being 0.00
+        DocNo := LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, true);
