+    [Test]
+    [Scope('OnPrem')]
+    procedure MfgOverheadCostCalculatedCorrectlyWithMultipleProdOrderLines()
+    var
+        RawItem: Record Item;
+        FGItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        MfgCostCalculationMgt: Codeunit "Mfg. Cost Calculation Mgt.";
+        ShareOfTotalCapCost: Decimal;
+        ExpMatCost: Decimal;
+        ExpCapDirCost: Decimal;
+        ExpSubDirCost: Decimal;
+        ExpCapOvhdCost: Decimal;
+        ExpMfgOvhdCost: Decimal;
+        TotalExpMfgOvhdCost: Decimal;
+        TotalExpMatCost: Decimal;
+        ExpectedMfgOvhdCost: Decimal;
+        LineQty: Decimal;
+        IndirectCostPct: Decimal;
+        RawItemUnitCost: Decimal;
+    begin
+        // [SCENARIO] Manufacturing overhead is calculated correctly in production order statistics when there are multiple production order lines
+        // Bug: When a production order has multiple lines for the same item, the manufacturing overhead was incorrectly accumulated
+        // Expected: Manufacturing overhead = Indirect Cost % * Total Material Cost, regardless of number of lines
+        Initialize();
+
+        // [GIVEN] RAW item with Unit Cost = 100
+        RawItemUnitCost := 100;
+        LibraryInventory.CreateItem(RawItem);
+        RawItem.Validate("Unit Cost", RawItemUnitCost);
+        RawItem.Modify(true);
+
+        // [GIVEN] Production BOM with RAW item, Qty per = 1
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, RawItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, RawItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] FG item with Indirect Cost % = 10, assigned to Production BOM
+        IndirectCostPct := 10;
+        LibraryInventory.CreateItem(FGItem);
+        FGItem.Validate("Replenishment System", FGItem."Replenishment System"::"Prod. Order");
+        FGItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FGItem.Validate("Indirect Cost %", IndirectCostPct);
+        FGItem.Modify(true);
+
+        // [GIVEN] Released production order with two lines, each with Qty = 10 (total = 20)
+        LineQty := 10;
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item,
+            FGItem."No.", 0);
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', LineQty);
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', LineQty);
+
+        // [GIVEN] Refresh production order (components only, not lines)
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, false, true, true, false);
+
+        // [WHEN] Calculate expected costs for all production order lines
+        TotalExpMfgOvhdCost := 0;
+        TotalExpMatCost := 0;
+        ProdOrderLine.SetRange(Status, ProductionOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder."No.");
+        if ProdOrderLine.FindSet() then
+            repeat
+                ExpMatCost := 0;
+                ExpCapDirCost := 0;
+                ExpSubDirCost := 0;
+                ExpCapOvhdCost := 0;
+                ExpMfgOvhdCost := 0;
+                MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+                MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+                    ProdOrderLine, ShareOfTotalCapCost, ExpMatCost, ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCost);
+                TotalExpMfgOvhdCost += ExpMfgOvhdCost;
+                TotalExpMatCost += ExpMatCost;
+            until ProdOrderLine.Next() = 0;
+
+        // [THEN] Total material cost = 2000 (20 qty * 100 unit cost)
+        Assert.AreEqual(
+            2 * LineQty * RawItemUnitCost,
+            TotalExpMatCost,
+            'Total expected material cost should be 2000');
+
+        // [THEN] Manufacturing overhead = 200 (10% of 2000), NOT 300 (which was the bug)
+        ExpectedMfgOvhdCost := Round(TotalExpMatCost * IndirectCostPct / 100);
+        Assert.AreEqual(
+            ExpectedMfgOvhdCost,
+            TotalExpMfgOvhdCost,
+            'Manufacturing overhead should be calculated as Indirect Cost % of Material Cost, not accumulated incorrectly across lines');
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";

