+        // [FEATURE] [Replan Production Order] [Input Quantity] [Output]
+        // [SCENARIO 101005] When replanning a Released Production Order after posting partial output, 
+        // the Input Quantity on Prod. Order Routing Line should be recalculated based on Remaining Quantity.
+        Initialize();
+
+        // [GIVEN] Create and certify routing "R" with setup time and run time.
+        LibraryManufacturing.CreateWorkCenterWithCalendar(WorkCenter);
