+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, Item."No.", Quantity);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [GIVEN] Post partial output (e.g. 20 out of 50).
+        OutputQty := Round(Quantity * LibraryRandom.RandDecInRange(0.3, 0.5, 2), 1);
+        CreateAndPostOutputJournalWithItemTracking(ProductionOrder."No.", false, OutputQty);
