--- /dev/null
+++ b/App/Layers/W1/Tests/Job/PurchDocFromJobTests.Codeunit.al
@@ -0,0 +1,119 @@
+// ------------------------------------------------------------------------------------------------
+// Copyright (c) Microsoft Corporation. All rights reserved.
+// Licensed under the MIT License. See License.txt in the project root for license information.
+// ------------------------------------------------------------------------------------------------
+codeunit 136399 "Purch Doc From Job Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase] [Job] [Purchase Doc. From Job]
+    end;
+
+    var
+        LibraryJob: Codeunit "Library - Job";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ContractEntryNoFilterSortedByEntryNoMatchesAllLines()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobPlanningLine: Record "Job Planning Line";
+        JobPlanningLine2: Record "Job Planning Line";
+        Item: Record Item;
+        Item2: Record Item;
+        SelectionFilterMgt: Codeunit System.Text.SelectionFilterManagement;
+        RecRef: RecordRef;
+        ContractEntryNoFilter: Text;
+        FirstContractEntryNo: Integer;
+        SecondContractEntryNo: Integer;
+    begin
+        // [SCENARIO] Filter generation for Job Contract Entry No. should work correctly when Job Planning Lines 
+        // are created out of order (inserting a line before an existing line).
+        // The fix in CreateContractEntryNoFilter ensures SetCurrentKey("Job Contract Entry No.") is called 
+        // before generating the filter, so it produces a valid ascending range like "15..16" instead of "16..15".
+
+        // [GIVEN] A Job with a Job Task
+        Initialize();
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItem(Item2);
+
+        // [GIVEN] First Job Planning Line is created (gets "Job Contract Entry No." = N)
+        LibraryJob.CreateJobPlanningLine(
+            JobPlanningLine."Line Type"::Budget,
+            JobPlanningLine.Type::Item,
+            JobTask,
+            JobPlanningLine);
+        JobPlanningLine.Validate("No.", Item."No.");
+        JobPlanningLine.Validate(Quantity, LibraryRandom.RandDec(10, 2));
+        JobPlanningLine.Modify(true);
+        FirstContractEntryNo := JobPlanningLine."Job Contract Entry No.";
+
+        // [GIVEN] A second Job Planning Line is inserted BEFORE the first line (higher Contract Entry No., lower Line No.)
+        // This reproduces the bug scenario from issue: "Create Purchase Order from Project not working 
+        // as expected if we add Project Planning Lines before the previous ones"
+        JobPlanningLine2.Init();
+        JobPlanningLine2.Validate("Job No.", JobTask."Job No.");
+        JobPlanningLine2.Validate("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine2.Validate("Line No.", JobPlanningLine."Line No." - 5000);
+        JobPlanningLine2.Insert(true);
+        JobPlanningLine2.Validate("Line Type", JobPlanningLine2."Line Type"::Budget);
+        JobPlanningLine2.Validate(Type, JobPlanningLine2.Type::Item);
+        JobPlanningLine2.Validate("No.", Item2."No.");
+        JobPlanningLine2.Validate(Quantity, LibraryRandom.RandDec(10, 2));
+        JobPlanningLine2.Modify(true);
+        SecondContractEntryNo := JobPlanningLine2."Job Contract Entry No.";
+
+        // [VERIFY] Precondition: Line order differs from Contract Entry No. order (this causes the bug)
+        Assert.IsTrue(SecondContractEntryNo > FirstContractEntryNo, 'Second line should have higher Contract Entry No.');
+        Assert.IsTrue(JobPlanningLine2."Line No." < JobPlanningLine."Line No.", 'Second line should have lower Line No.');
+
+        // [WHEN] Filter is generated with SetCurrentKey on Job Contract Entry No.
+        // This replicates the fix in CreateContractEntryNoFilter procedure of "Purchase Doc. From Job" codeunit
+        JobPlanningLine.Reset();
+        JobPlanningLine.SetLoadFields("Job Contract Entry No.");
+        JobPlanningLine.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLine.SetRange("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine.SetCurrentKey("Job Contract Entry No.");
+        JobPlanningLine.FindSet();
+        RecRef.GetTable(JobPlanningLine);
+        ContractEntryNoFilter := SelectionFilterMgt.GetSelectionFilter(RecRef, JobPlanningLine.FieldNo("Job Contract Entry No."));
+
+        // [THEN] The filter should correctly match both Job Planning Lines
+        // The filter should be in format "FirstContractEntryNo..SecondContractEntryNo" (e.g., "15..16")
+        // which matches both records, not "16..15" which would match none
+        JobPlanningLine.Reset();
+        JobPlanningLine.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLine.SetRange("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine.SetFilter("Job Contract Entry No.", ContractEntryNoFilter);
+        Assert.AreEqual(2, JobPlanningLine.Count(), 'Filter should match both Job Planning Lines when sorted by Contract Entry No.');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"Purch Doc From Job Tests");
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"Purch Doc From Job Tests");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"Purch Doc From Job Tests");
+    end;
+}

