+        ReservEntry.SetRange("Source Subtype", SalesHeaderInvoice."Document Type");
+        ReservEntry.SetRange("Source ID", SalesHeaderInvoice."No.");
+        ReservEntry.SetRange("Source Ref. No.", SalesLineInvoice."Line No.");
+        ReservEntry.SetRange("Item No.", Item."No.");
