+        CreateAndReleaseSalesOrder(
+          SalesHeader[1], '', Item."No.", Quantity, LocationWhite.Code, '', false, ReservationMode::AutoReserve);
+
+        // [GIVEN] Second Sales Order for same Quantity, released.
+        CreateAndReleaseSalesOrder(
+          SalesHeader[2], '', Item."No.", Quantity, LocationWhite.Code, '', false, ReservationMode::" ");
+
+        // [GIVEN] Warehouse Shipment and Pick created from second Sales Order. FEFO assigns lot with earliest expiration date.
+        CreateWarehouseShipmentFromSalesHeader(SalesHeader[2]);
+        CreatePickFromWarehouseShipment(WarehouseShipmentLine."Source Document"::"Sales Order", SalesHeader[2]."No.");
+
+        // [WHEN] Register Pick.
+        FindWarehouseActivityLine(
