+// ------------------------------------------------------------------------------------------------
+codeunit 139491 "SCM Whse Shpt Preview Transfer"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse Shipment] [Transfer Order] [Preview Posting]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        IsInitialized: Boolean;
+        WrongPostPreviewErr: Label 'Expected empty error from Preview. Actual error: ';
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PreviewWhseShptForTransferOrderDoesNotDeleteShipmentLine()
+    var
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        WarehouseShipmentHeader: Record "Warehouse Shipment Header";
+        WarehouseShipmentLine: Record "Warehouse Shipment Line";
+        FromLocation: Record Location;
+        ToLocation: Record Location;
+        WhsePostShipmentYesNo: Codeunit "Whse.-Post Shipment (Yes/No)";
+        GLPostingPreview: TestPage "G/L Posting Preview";
+        WhseShipmentNo: Code[20];
+    begin
+        // [FEATURE] [Transfer] [Warehouse Shipment] [Preview Posting]
+        // [SCENARIO] Preview Warehouse Shipment posting for Transfer Order should not remove the warehouse shipment line.
+        // Bug: After preview posting, the warehouse shipment line linked to a transfer order was disappearing.
+        Initialize();
+
+        // [GIVEN] Location with 'Require Shipment' enabled and Warehouse Employee setup
+        CreateLocationWMSWithWhseEmployee(FromLocation, false, false, false, false, true);
+        CreateLocationWMSWithWhseEmployee(ToLocation, false, false, false, false, false);
+
+        // [GIVEN] Transfer Order from FromLocation to ToLocation with inventory
+        CreateTransferOrderWithLineLocation(TransferHeader, TransferLine, FromLocation.Code, ToLocation.Code);
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [GIVEN] Warehouse Shipment created from Transfer Order
+        LibraryWarehouse.CreateWhseShipmentFromTO(TransferHeader);
+        FindWarehouseShipmentLine(WarehouseShipmentLine, TransferHeader."No.");
+        WhseShipmentNo := WarehouseShipmentLine."No.";
+        WarehouseShipmentHeader.Get(WhseShipmentNo);
+        Commit();
+
+        // [WHEN] Preview posting is invoked on the warehouse shipment
+        GLPostingPreview.Trap();
+        asserterror WhsePostShipmentYesNo.Preview(WarehouseShipmentLine);
+        Assert.AreEqual('', GetLastErrorText, WrongPostPreviewErr + GetLastErrorText);
+        GLPostingPreview.OK().Invoke();
+
+        // [THEN] The warehouse shipment header still exists
+        Assert.IsTrue(WarehouseShipmentHeader.Get(WhseShipmentNo), 'Warehouse Shipment Header should still exist after preview posting.');
+
+        // [THEN] The warehouse shipment line still exists and is linked to the transfer order
+        WarehouseShipmentLine.Reset();
+        WarehouseShipmentLine.SetRange("No.", WhseShipmentNo);
+        WarehouseShipmentLine.SetRange("Source No.", TransferHeader."No.");
+        Assert.IsTrue(WarehouseShipmentLine.FindFirst(), 'Warehouse Shipment Line should still exist after preview posting.');
+        Assert.AreEqual(TransferHeader."No.", WarehouseShipmentLine."Source No.", 'Warehouse Shipment Line should still be linked to the Transfer Order.');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PreviewWhseShptMultipleTimesForTransferOrderDoesNotDeleteShipmentLine()
+    var
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        WarehouseShipmentHeader: Record "Warehouse Shipment Header";
+        WarehouseShipmentLine: Record "Warehouse Shipment Line";
+        FromLocation: Record Location;
+        ToLocation: Record Location;
+        WhsePostShipmentYesNo: Codeunit "Whse.-Post Shipment (Yes/No)";
+        GLPostingPreview: TestPage "G/L Posting Preview";
+        WhseShipmentNo: Code[20];
+        i: Integer;
+    begin
+        // [FEATURE] [Transfer] [Warehouse Shipment] [Preview Posting]
+        // [SCENARIO] Preview Warehouse Shipment posting multiple times for Transfer Order should not remove the warehouse shipment line.
+        Initialize();
+
+        // [GIVEN] Location with 'Require Shipment' enabled and Warehouse Employee setup
+        CreateLocationWMSWithWhseEmployee(FromLocation, false, false, false, false, true);
+        CreateLocationWMSWithWhseEmployee(ToLocation, false, false, false, false, false);
+
+        // [GIVEN] Transfer Order from FromLocation to ToLocation with inventory
+        CreateTransferOrderWithLineLocation(TransferHeader, TransferLine, FromLocation.Code, ToLocation.Code);
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [GIVEN] Warehouse Shipment created from Transfer Order
+        LibraryWarehouse.CreateWhseShipmentFromTO(TransferHeader);
+        FindWarehouseShipmentLine(WarehouseShipmentLine, TransferHeader."No.");
+        WhseShipmentNo := WarehouseShipmentLine."No.";
+        WarehouseShipmentHeader.Get(WhseShipmentNo);
+        Commit();
+
+        // [WHEN] Preview posting is invoked multiple times on the warehouse shipment
+        for i := 1 to 3 do begin
+            GLPostingPreview.Trap();
+            asserterror WhsePostShipmentYesNo.Preview(WarehouseShipmentLine);
+            Assert.AreEqual('', GetLastErrorText, WrongPostPreviewErr + GetLastErrorText);
+            GLPostingPreview.OK().Invoke();
+        end;
+
+        // [THEN] The warehouse shipment header still exists after multiple previews
+        Assert.IsTrue(WarehouseShipmentHeader.Get(WhseShipmentNo), 'Warehouse Shipment Header should still exist after multiple preview postings.');
+
+        // [THEN] The warehouse shipment line still exists and is linked to the transfer order
+        WarehouseShipmentLine.Reset();
+        WarehouseShipmentLine.SetRange("No.", WhseShipmentNo);
+        WarehouseShipmentLine.SetRange("Source No.", TransferHeader."No.");
+        Assert.IsTrue(WarehouseShipmentLine.FindFirst(), 'Warehouse Shipment Line should still exist after multiple preview postings.');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Whse Shpt Preview Transfer");
+        WarehouseEmployee.DeleteAll();
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Whse Shpt Preview Transfer");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateLocalData();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Whse Shpt Preview Transfer");
+    end;
+
+    local procedure CreateLocationWMSWithWhseEmployee(var Location: Record Location; BinMandatory: Boolean; RequirePutAway: Boolean; RequirePick: Boolean; RequireReceive: Boolean; RequireShipment: Boolean)
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        LibraryWarehouse.CreateLocationWMS(Location, BinMandatory, RequirePutAway, RequirePick, RequireReceive, RequireShipment);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+    end;
+
+    local procedure CreateTransferOrderWithLineLocation(var TransferHeader: Record "Transfer Header"; var TransferLine: Record "Transfer Line"; FromLocationCode: Code[10]; ToLocationCode: Code[10])
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        Item: Record Item;
+        InTransitLocation: Record Location;
+    begin
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemJournalLineInItemTemplate(
+          ItemJournalLine, Item."No.", FromLocationCode, '', LibraryRandom.RandIntInRange(10, 20));
+        LibraryInventory.PostItemJournalLine(
+          ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        LibraryWarehouse.CreateInTransitLocation(InTransitLocation);
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, FromLocationCode, ToLocationCode, InTransitLocation.Code);
+        LibraryWarehouse.CreateTransferLine(TransferHeader, TransferLine, Item."No.", LibraryRandom.RandInt(5));
+    end;
+
+    local procedure FindWarehouseShipmentLine(var WarehouseShipmentLine: Record "Warehouse Shipment Line"; DocumentNo: Code[20])
+    begin
+        WarehouseShipmentLine.SetRange("Source No.", DocumentNo);
+        WarehouseShipmentLine.FindFirst();
+    end;
+}

