diff --git a/App/Layers/W1/Tests/ERM/ReopenIncomingDocumentTests.Codeunit.al b/App/Layers/W1/Tests/ERM/ReopenIncomingDocumentTests.Codeunit.al
new file mode 100644
index 00000000..235f862f
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/ReopenIncomingDocumentTests.Codeunit.al
@@ -0,0 +1,129 @@
+codeunit 134499 "Reopen Incoming Document Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Incoming Documents] [Reopen]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryIncomingDocuments: Codeunit "Library - Incoming Documents";
+        LibraryPurchase: Codeunit "Library - Purchase";
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ReopenCreatedIncomingDocWithRelatedRecordKeepsStatusCreated()
+    var
+        IncomingDocument: Record "Incoming Document";
+        PurchaseHeader: Record "Purchase Header";
+        Vendor: Record Vendor;
+        ReleaseIncomingDocument: Codeunit "Release Incoming Document";
+    begin
+        // [SCENARIO] When an Incoming Document with status "Created" is reopened and the related record still exists,
+        // the status should remain "Created" instead of being reset to "New".
+
+        // [GIVEN] An Incoming Document with status "Created" and a linked Purchase Invoice that exists
+        CreateNewIncomingDocument(IncomingDocument);
+        IncomingDocument.Release();
+        IncomingDocument.Modify();
+
+        // Create a Purchase Invoice linked to this Incoming Document
+        LibraryPurchase.CreateVendor(Vendor);
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Invoice, Vendor."No.");
+        PurchaseHeader."Incoming Document Entry No." := IncomingDocument."Entry No.";
+        PurchaseHeader.Modify();
+
+        // Set up the Incoming Document to reflect that a document was created
+        IncomingDocument."Document Type" := IncomingDocument."Document Type"::"Purchase Invoice";
+        IncomingDocument."Document No." := PurchaseHeader."No.";
+        IncomingDocument.Modify();
+
+        // Mark the document as "Created" using the ReleaseIncomingDocument codeunit
+        ReleaseIncomingDocument.Create(IncomingDocument);
+        IncomingDocument.Get(IncomingDocument."Entry No.");
+        Assert.AreEqual(IncomingDocument.Status::Created, IncomingDocument.Status, 'Initial status should be Created');
+
+        // [WHEN] Reopen is called on the Incoming Document
+        ReleaseIncomingDocument.Reopen(IncomingDocument);
+        IncomingDocument.Get(IncomingDocument."Entry No.");
+
+        // [THEN] The status should remain "Created" because the related record still exists
+        Assert.AreEqual(
+            IncomingDocument.Status::Created,
+            IncomingDocument.Status,
+            'Status should remain Created when related record exists');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ReopenCreatedIncomingDocWithNoRelatedRecordSetsStatusNew()
+    var
+        IncomingDocument: Record "Incoming Document";
+        ReleaseIncomingDocument: Codeunit "Release Incoming Document";
+    begin
+        // [SCENARIO] When an Incoming Document with status "Created" is reopened but the related record
+        // does not exist, the status should be reset to "New".
+
+        // [GIVEN] An Incoming Document with status "Created" but no existing related record
+        CreateNewIncomingDocument(IncomingDocument);
+        IncomingDocument.Release();
+        IncomingDocument.Modify();
+
+        // Set up the Incoming Document to reflect that a document was "created" but the related record doesn't exist
+        IncomingDocument."Document Type" := IncomingDocument."Document Type"::"Purchase Invoice";
+        IncomingDocument."Document No." := 'NON-EXISTENT-DOC';
+        IncomingDocument.Modify();
+
+        // Mark the document as "Created"
+        ReleaseIncomingDocument.Create(IncomingDocument);
+        IncomingDocument.Get(IncomingDocument."Entry No.");
+        Assert.AreEqual(IncomingDocument.Status::Created, IncomingDocument.Status, 'Initial status should be Created');
+
+        // [WHEN] Reopen is called on the Incoming Document
+        ReleaseIncomingDocument.Reopen(IncomingDocument);
+        IncomingDocument.Get(IncomingDocument."Entry No.");
+
+        // [THEN] The status should be reset to "New" because the related record does not exist
+        Assert.AreEqual(
+            IncomingDocument.Status::New,
+            IncomingDocument.Status,
+            'Status should be New when related record does not exist');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ReopenReleasedIncomingDocSetsStatusNew()
+    var
+        IncomingDocument: Record "Incoming Document";
+        ReleaseIncomingDocument: Codeunit "Release Incoming Document";
+    begin
+        // [SCENARIO] When an Incoming Document with status "Released" is reopened,
+        // the status should be reset to "New" (existing behavior).
+
+        // [GIVEN] An Incoming Document with status "Released"
+        CreateNewIncomingDocument(IncomingDocument);
+        IncomingDocument.Release();
+        IncomingDocument.Get(IncomingDocument."Entry No.");
+        Assert.AreEqual(IncomingDocument.Status::Released, IncomingDocument.Status, 'Initial status should be Released');
+
+        // [WHEN] Reopen is called on the Incoming Document
+        ReleaseIncomingDocument.Reopen(IncomingDocument);
+        IncomingDocument.Get(IncomingDocument."Entry No.");
+
+        // [THEN] The status should be reset to "New"
+        Assert.AreEqual(
+            IncomingDocument.Status::New,
+            IncomingDocument.Status,
+            'Status should be New after reopening from Released');
+    end;
+
+    local procedure CreateNewIncomingDocument(var IncomingDocument: Record "Incoming Document")
+    begin
+        LibraryIncomingDocuments.InitIncomingDocuments();
+        LibraryIncomingDocuments.CreateNewIncomingDocument(IncomingDocument);
+        Commit();
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMMfgSKULowLevelCode.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMMfgSKULowLevelCode.Codeunit.al
new file mode 100644
index 00000000..2903f49c
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMMfgSKULowLevelCode.Codeunit.al
@@ -0,0 +1,195 @@
+codeunit 137932 "SCM Mfg. SKU Low-Level Code"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [SKU] [Low-Level Code] [SCM]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcRegenPlanPlansComponentWhenSKUHasProductionBOM()
+    var
+        ComponentItem: Record Item;
+        MainItem: Record Item;
+        Location: Record Location;
+        StockkeepingUnit: Record "Stockkeeping Unit";
+        ComponentSKU: Record "Stockkeeping Unit";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ManufacturingSetup: Record "Manufacturing Setup";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionLine: Record "Requisition Line";
+        SalesQty: Decimal;
+    begin
+        // [SCENARIO] When Calculate Regenerative Plan is run in a planning worksheet, 
+        // the component should be planned in the first run when Stockkeeping Units are setup for items.
+        // Bug: Previously, the component was not planned on first run because the low-level code 
+        // was not being calculated when Production BOM No. was set on SKU instead of on Item.
+        Initialize();
+
+        // [GIVEN] Enable Dynamic Low-Level Code in Manufacturing Setup.
+        ManufacturingSetup.Get();
+        ManufacturingSetup.Validate("Dynamic Low-Level Code", true);
+        ManufacturingSetup.Modify(true);
+
+        // [GIVEN] Create a Location.
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+
+        // [GIVEN] Create Component Item.
+        LibraryManufacturing.CreateItemManufacturing(
+            ComponentItem, "Costing Method"::Standard, 0, "Reordering Policy"::Order, "Flushing Method"::Manual, '', '');
+
+        // [GIVEN] Create Main Item.
+        LibraryManufacturing.CreateItemManufacturing(
+            MainItem, "Costing Method"::Standard, 0, "Reordering Policy"::"Lot-for-Lot", "Flushing Method"::Manual, '', '');
+
+        // [GIVEN] Create Production BOM with Component Item.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, MainItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', "Production BOM Line Type"::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, "BOM Status"::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] Create SKU for Component Item at Location with Purchase replenishment and Order reorder policy.
+        CreateSKU(ComponentSKU, ComponentItem."No.", Location.Code);
+        ComponentSKU.Validate("Replenishment System", ComponentSKU."Replenishment System"::Purchase);
+        ComponentSKU.Validate("Reordering Policy", ComponentSKU."Reordering Policy"::Order);
+        ComponentSKU.Modify(true);
+
+        // [GIVEN] Create SKU for Main Item at Location with Prod. Order replenishment, Lot-for-Lot reorder policy, and Production BOM.
+        CreateSKU(StockkeepingUnit, MainItem."No.", Location.Code);
+        StockkeepingUnit.Validate("Replenishment System", StockkeepingUnit."Replenishment System"::"Prod. Order");
+        StockkeepingUnit.Validate("Reordering Policy", StockkeepingUnit."Reordering Policy"::"Lot-for-Lot");
+        StockkeepingUnit.Validate("Manufacturing Policy", StockkeepingUnit."Manufacturing Policy"::"Make-to-Stock");
+        StockkeepingUnit.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        StockkeepingUnit.Modify(true);
+
+        // [GIVEN] Create Sales Order for Main Item at the Location.
+        SalesQty := LibraryRandom.RandInt(10);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, MainItem."No.", SalesQty);
+        SalesLine.Validate("Location Code", Location.Code);
+        SalesLine.Modify(true);
+
+        // [WHEN] Calculate Regenerative Plan for both items.
+        MainItem.SetFilter("No.", '%1|%2', MainItem."No.", ComponentItem."No.");
+        MainItem.SetFilter("Location Filter", Location.Code);
+        LibraryPlanning.CalcRegenPlanForPlanWksh(MainItem, WorkDate(), CalcDate('<+1Y>', WorkDate()));
+
+        // [THEN] Requisition Line exists for Main Item (Production Order).
+        RequisitionLine.SetRange("No.", MainItem."No.");
+        RequisitionLine.SetRange("Location Code", Location.Code);
+        Assert.IsFalse(RequisitionLine.IsEmpty(), 'Requisition Line for Main Item must be found.');
+
+        // [THEN] Requisition Line exists for Component Item (Purchase) - this is the key verification.
+        // Without the fix, this line would NOT be created on the first Calculate Regenerative Plan run.
+        RequisitionLine.SetRange("No.", ComponentItem."No.");
+        RequisitionLine.SetRange("Location Code", Location.Code);
+        Assert.IsFalse(RequisitionLine.IsEmpty(), 'Requisition Line for Component Item must be found on first Calculate Regenerative Plan run.');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure SKUProductionBOMValidationUpdatesLowLevelCode()
+    var
+        ComponentItem: Record Item;
+        MainItem: Record Item;
+        Location: Record Location;
+        StockkeepingUnit: Record "Stockkeeping Unit";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ManufacturingSetup: Record "Manufacturing Setup";
+    begin
+        // [SCENARIO] When Production BOM No. is validated on a Stockkeeping Unit, 
+        // the low-level code should be calculated dynamically to ensure proper planning order.
+        Initialize();
+
+        // [GIVEN] Enable Dynamic Low-Level Code in Manufacturing Setup.
+        ManufacturingSetup.Get();
+        ManufacturingSetup.Validate("Dynamic Low-Level Code", true);
+        ManufacturingSetup.Modify(true);
+
+        // [GIVEN] Create a Location.
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+
+        // [GIVEN] Create Component Item with Low-Level Code = 0.
+        LibraryManufacturing.CreateItemManufacturing(
+            ComponentItem, "Costing Method"::Standard, 0, "Reordering Policy"::Order, "Flushing Method"::Manual, '', '');
+        ComponentItem."Low-Level Code" := 0;
+        ComponentItem.Modify();
+
+        // [GIVEN] Create Main Item with Low-Level Code = 0.
+        LibraryManufacturing.CreateItemManufacturing(
+            MainItem, "Costing Method"::Standard, 0, "Reordering Policy"::"Lot-for-Lot", "Flushing Method"::Manual, '', '');
+        MainItem."Low-Level Code" := 0;
+        MainItem.Modify();
+
+        // [GIVEN] Create Certified Production BOM with Component Item.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, MainItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', "Production BOM Line Type"::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, "BOM Status"::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] Create SKU for Main Item.
+        CreateSKU(StockkeepingUnit, MainItem."No.", Location.Code);
+        StockkeepingUnit.Validate("Replenishment System", StockkeepingUnit."Replenishment System"::"Prod. Order");
+
+        // [WHEN] Set Production BOM No. on the SKU.
+        StockkeepingUnit.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        StockkeepingUnit.Modify(true);
+
+        // [THEN] Main Item Low-Level Code should be set (greater than or equal to 0, typically 0 for parent items).
+        MainItem.Get(MainItem."No.");
+        // The parent item gets low-level code calculated based on its position in the BOM hierarchy.
+
+        // [THEN] Production BOM Header Low-Level Code should be updated (1 for a BOM attached to a level 0 item).
+        ProductionBOMHeader.Get(ProductionBOMHeader."No.");
+        Assert.IsTrue(
+            ProductionBOMHeader."Low-Level Code" >= 1,
+            'Production BOM Low-Level Code must be set when Production BOM No. is validated on SKU.');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Mfg. SKU Low-Level Code");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Mfg. SKU Low-Level Code");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryPlanning.SetCombinedMPSMRPCalculation(true);
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Mfg. SKU Low-Level Code");
+    end;
+
+    local procedure CreateSKU(var StockkeepingUnit: Record "Stockkeeping Unit"; ItemNo: Code[20]; LocationCode: Code[10])
+    begin
+        StockkeepingUnit.Init();
+        StockkeepingUnit.Validate("Item No.", ItemNo);
+        StockkeepingUnit.Validate("Location Code", LocationCode);
+        StockkeepingUnit.Insert(true);
+    end;
+}

