diff --git a/App/Layers/W1/Tests/SCM/SCMInventoryOrderTracking.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMInventoryOrderTracking.Codeunit.al
index 70c0068a..3b8a25b5 100644
--- a/App/Layers/W1/Tests/SCM/SCMInventoryOrderTracking.Codeunit.al
+++ b/App/Layers/W1/Tests/SCM/SCMInventoryOrderTracking.Codeunit.al
@@ -645,6 +645,97 @@ codeunit 137250 "SCM Inventory Order Tracking"
         LibraryVariableStorage.AssertEmpty();
     end;

+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcReservationQuantityIncludesTrackingEntries()
+    var
+        ReservationEntry: Record "Reservation Entry";
+        ReservationEntry2: Record "Reservation Entry";
+        ReservationEntry3: Record "Reservation Entry";
+        QtyPerUoM: Decimal;
+        BaseQty1: Decimal;
+        BaseQty2: Decimal;
+        BaseQty3: Decimal;
+        TotalQuantity: Decimal;
+    begin
+        // [FEATURE] [Order Tracking] [Reservation Entry]
+        // [SCENARIO] When multiple Tracking reservation entries exist for the same source with Qty. per Unit of Measure > 1,
+        // the Quantity calculation should include all Tracking entries to prevent rounding errors.
+        // Bug: CalcReservationQuantity only filtered for Reservation status, not Tracking status.
+        // This caused rounding issues when tracking lines are split into multiple entries where sum of Quantity = 12.00001 instead of 12.
+        Initialize();
+
+        // [GIVEN] Qty. per Unit of Measure = 24 (CASE = 24 PCS)
+        QtyPerUoM := 24;
+
+        // [GIVEN] Total of 288 base quantity (12 CASES) split into 3 tracking entries
+        // These values reproduce the rounding issue from the bug report
+        BaseQty1 := 13;
+        BaseQty2 := 137.54167;
+        BaseQty3 := 137.45833;
+
+        // [GIVEN] Create first reservation entry with Tracking status
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := 1;
+        ReservationEntry.Positive := false;
+        ReservationEntry."Reservation Status" := ReservationEntry."Reservation Status"::Tracking;
+        ReservationEntry."Source Type" := Database::"Sales Line";
+        ReservationEntry."Source Subtype" := 1; // Order
+        ReservationEntry."Source ID" := 'TEST-ORDER';
+        ReservationEntry."Source Ref. No." := 10000;
+        ReservationEntry."Source Batch Name" := '';
+        ReservationEntry."Source Prod. Order Line" := 0;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUoM;
+        ReservationEntry.Validate("Quantity (Base)", -BaseQty1);
+        ReservationEntry.Insert();
+
+        // [GIVEN] Create second reservation entry with Tracking status for the same source
+        ReservationEntry2.Init();
+        ReservationEntry2."Entry No." := 2;
+        ReservationEntry2.Positive := false;
+        ReservationEntry2."Reservation Status" := ReservationEntry2."Reservation Status"::Tracking;
+        ReservationEntry2."Source Type" := Database::"Sales Line";
+        ReservationEntry2."Source Subtype" := 1; // Order
+        ReservationEntry2."Source ID" := 'TEST-ORDER';
+        ReservationEntry2."Source Ref. No." := 10000;
+        ReservationEntry2."Source Batch Name" := '';
+        ReservationEntry2."Source Prod. Order Line" := 0;
+        ReservationEntry2."Qty. per Unit of Measure" := QtyPerUoM;
+        ReservationEntry2.Validate("Quantity (Base)", -BaseQty2);
+        ReservationEntry2.Insert();
+
+        // [GIVEN] Create third reservation entry with Tracking status for the same source
+        ReservationEntry3.Init();
+        ReservationEntry3."Entry No." := 3;
+        ReservationEntry3.Positive := false;
+        ReservationEntry3."Reservation Status" := ReservationEntry3."Reservation Status"::Tracking;
+        ReservationEntry3."Source Type" := Database::"Sales Line";
+        ReservationEntry3."Source Subtype" := 1; // Order
+        ReservationEntry3."Source ID" := 'TEST-ORDER';
+        ReservationEntry3."Source Ref. No." := 10000;
+        ReservationEntry3."Source Batch Name" := '';
+        ReservationEntry3."Source Prod. Order Line" := 0;
+        ReservationEntry3."Qty. per Unit of Measure" := QtyPerUoM;
+        ReservationEntry3.Validate("Quantity (Base)", -BaseQty3);
+        ReservationEntry3.Insert();
+
+        // [WHEN] Sum all Quantity fields from the reservation entries
+        ReservationEntry.Get(1, false);
+        ReservationEntry2.Get(2, false);
+        ReservationEntry3.Get(3, false);
+        TotalQuantity := Abs(ReservationEntry.Quantity) + Abs(ReservationEntry2.Quantity) + Abs(ReservationEntry3.Quantity);
+
+        // [THEN] The total Quantity should equal exactly 12 (288 / 24), not 12.00001
+        // With the fix, CalcReservationQuantity includes Tracking entries when calculating the quantity,
+        // ensuring the last entry gets the correct value to make the total exact.
+        Assert.AreEqual(12, TotalQuantity, 'Total Quantity must be exactly 12. CalcReservationQuantity should include Tracking entries to prevent rounding errors.');
+
+        // Cleanup
+        ReservationEntry.Delete();
+        ReservationEntry2.Delete();
+        ReservationEntry3.Delete();
+    end;
+
