+    [Test]
+    procedure TrialBalanceBufferClearsDebitCreditOnValueChange()
+    var
+        TrialBalanceBuffer: Record "EXR Trial Balance Buffer";
+    begin
+        // [SCENARIO] When dimension breakdown iterates over multiple dimension values, 
+        // the debit/credit values should not carry over from previous iterations
+        // Bug: Excel layouts - dim breakdown results in repeated values (Trial Balance report)
+
+        // [GIVEN] A Trial Balance Buffer record with a positive Net Change (sets Debit, not Credit)
+        TrialBalanceBuffer.Init();
+        TrialBalanceBuffer."G/L Account No." := 'TEST001';
+        TrialBalanceBuffer."Dimension 1 Code" := 'DIM1';
+        TrialBalanceBuffer.Validate("Net Change", 100);
+        TrialBalanceBuffer.Validate(Balance, 200);
+
+        // [THEN] Debit values should be set, Credit values should be zero
+        Assert.AreEqual(100, TrialBalanceBuffer."Net Change (Debit)", 'Net Change Debit should be 100');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit)", 'Net Change Credit should be 0 initially');
+        Assert.AreEqual(200, TrialBalanceBuffer."Balance (Debit)", 'Balance Debit should be 200');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Credit)", 'Balance Credit should be 0 initially');
+
+        // [WHEN] The same record is reused (simulating next dimension iteration) 
+        // and Net Change becomes negative (should now set Credit, clear Debit)
+        TrialBalanceBuffer.Validate("Net Change", -50);
+        TrialBalanceBuffer.Validate(Balance, -75);
+
+        // [THEN] Credit values should be set, and Debit values should be cleared to zero
+        // Without the fix, Net Change (Debit) would still be 100 (stale value)
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Debit)", 'Net Change Debit should be cleared to 0 when value is negative');
+        Assert.AreEqual(50, TrialBalanceBuffer."Net Change (Credit)", 'Net Change Credit should be 50');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Debit)", 'Balance Debit should be cleared to 0 when value is negative');
+        Assert.AreEqual(75, TrialBalanceBuffer."Balance (Credit)", 'Balance Credit should be 75');
+
+        // [WHEN] Value changes back to positive
+        TrialBalanceBuffer.Validate("Net Change", 300);
+        TrialBalanceBuffer.Validate(Balance, 400);
+
+        // [THEN] Debit should be set, Credit should be cleared
+        Assert.AreEqual(300, TrialBalanceBuffer."Net Change (Debit)", 'Net Change Debit should be 300');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit)", 'Net Change Credit should be cleared to 0 when value is positive');
+        Assert.AreEqual(400, TrialBalanceBuffer."Balance (Debit)", 'Balance Debit should be 400');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Credit)", 'Balance Credit should be cleared to 0 when value is positive');
+    end;
+
+    [Test]
+    procedure TrialBalanceBufferClearsLastPeriodDebitCreditOnValueChange()
+    var
+        TrialBalanceBuffer: Record "EXR Trial Balance Buffer";
+    begin
+        // [SCENARIO] Last Period Net/Balance debit/credit values should also be properly cleared on sign change
+        // Bug: Excel layouts - dim breakdown results in repeated values
+
+        // [GIVEN] A Trial Balance Buffer with positive Last Period values
+        TrialBalanceBuffer.Init();
+        TrialBalanceBuffer."G/L Account No." := 'TEST002';
+        TrialBalanceBuffer.Validate("Last Period Net", 100);
+        TrialBalanceBuffer.Validate("Last Period Bal.", 200);
+
+        // [THEN] Debit values should be set
+        Assert.AreEqual(100, TrialBalanceBuffer."Last Period Net (Debit)", 'Last Period Net Debit should be 100');
+        Assert.AreEqual(0, TrialBalanceBuffer."Last Period Net (Credit)", 'Last Period Net Credit should be 0');
+        Assert.AreEqual(200, TrialBalanceBuffer."Last Period Bal. (Debit)", 'Last Period Bal Debit should be 200');
+        Assert.AreEqual(0, TrialBalanceBuffer."Last Period Bal. (Credit)", 'Last Period Bal Credit should be 0');
+
+        // [WHEN] Values become negative (simulating next dimension iteration with different values)
+        TrialBalanceBuffer.Validate("Last Period Net", -50);
+        TrialBalanceBuffer.Validate("Last Period Bal.", -75);
+
+        // [THEN] Credit values should be set, Debit values should be cleared
+        Assert.AreEqual(0, TrialBalanceBuffer."Last Period Net (Debit)", 'Last Period Net Debit should be cleared');
+        Assert.AreEqual(50, TrialBalanceBuffer."Last Period Net (Credit)", 'Last Period Net Credit should be 50');
+        Assert.AreEqual(0, TrialBalanceBuffer."Last Period Bal. (Debit)", 'Last Period Bal Debit should be cleared');
+        Assert.AreEqual(75, TrialBalanceBuffer."Last Period Bal. (Credit)", 'Last Period Bal Credit should be 75');
+    end;
+
+    [Test]
+    procedure TrialBalanceBufferClearsACYDebitCreditOnValueChange()
+    var
+        TrialBalanceBuffer: Record "EXR Trial Balance Buffer";
+    begin
+        // [SCENARIO] Additional Currency (ACY) debit/credit values should also be properly cleared on sign change
+        // Bug: Excel layouts - dim breakdown results in repeated values
+
