+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit) (ACY)", 'Net Change Credit ACY should be 0');
+        Assert.AreEqual(250, TrialBalanceBuffer."Balance (Debit) (ACY)", 'Balance Debit ACY should be 250');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Credit) (ACY)", 'Balance Credit ACY should be 0');
