+        TrialBalanceBuffer.Validate("Balance (ACY)", -120);
+
+        // [THEN] ACY Credit values should be set, ACY Debit values should be cleared
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Debit) (ACY)", 'Net Change Debit ACY should be cleared');
+        Assert.AreEqual(80, TrialBalanceBuffer."Net Change (Credit) (ACY)", 'Net Change Credit ACY should be 80');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Debit) (ACY)", 'Balance Debit ACY should be cleared');
+        Assert.AreEqual(120, TrialBalanceBuffer."Balance (Credit) (ACY)", 'Balance Credit ACY should be 120');
