+++ b/App/Layers/W1/Tests/SCM/SCMReservationReplanningFix.Codeunit.al
@@ -0,0 +1,266 @@
+codeunit 137499 "SCM Reservation Replanning Fix"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [Reservation] [Item Tracking] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ItemTrackingLinesAssignLotNoPageHandler')]
+    [Scope('OnPrem')]
+    procedure ReplanningItemWithNoPlanningResultsDoesNotCreateWrongSurplusEntries()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        RequisitionLine: Record "Requisition Line";
+        ReservationEntry: Record "Reservation Entry";
+        Vendor: Record Vendor;
+        SalesQty: Decimal;
+        PurchQty: Decimal;
+        SurplusCountBefore: Integer;
+        SurplusCountAfter: Integer;
+        ProspectCountAfter: Integer;
+    begin
+        // [SCENARIO] When recalculating an item in a requisition worksheet with no planning results,
+        // wrong surplus entries should not be created in the reservation table.
+        // This test validates the fix for the issue where replanning creates incorrect surplus entries
+        // for the extra quantity (beyond the original demand) when Planning Flexibility is set to None.
+
+        // [GIVEN] Create an item with Lot-for-Lot reordering policy, Purchase replenishment and Lot tracking
+        Initialize();
+        SalesQty := 100;
+        PurchQty := 150; // 50 more than sales demand
+
+        CreateItemWithLotTrackingAndLotForLotPolicy(Item);
+        LibraryPurchase.CreateVendor(Vendor);
+
+        // [GIVEN] Create a Sales Order for 100 PCS of the item (demand)
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", SalesQty);
+
+        // [GIVEN] Plan the item in the requisition worksheet to meet the demand
+        CalculatePlanForRequisitionWorksheet(Item);
+
+        // [GIVEN] Find and modify the requisition line:
+        // - Set Vendor No.
+        // - Change Quantity from 100 to 150
+        // - Set Planning Flexibility to None
+        FindRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate("Vendor No.", Vendor."No.");
+        RequisitionLine.Validate(Quantity, PurchQty);
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Modify(true);
+
+        // [GIVEN] Assign Lot No. to the requisition line item tracking
+        RequisitionLine.OpenItemTrackingLines();
+
+        // [GIVEN] Accept and carry out action message to create Purchase Order
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        // [GIVEN] Find the created Purchase Order
+        PurchaseLine.SetRange(Type, PurchaseLine.Type::Item);
+        PurchaseLine.SetRange("No.", Item."No.");
+        PurchaseLine.SetRange("Document Type", PurchaseLine."Document Type"::Order);
+        PurchaseLine.FindFirst();
+        PurchaseHeader.Get(PurchaseLine."Document Type", PurchaseLine."Document No.");
+
+        // [GIVEN] Count the number of Surplus reservation entries for the Purchase Line before replanning
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type"::Order.AsInteger());
+        ReservationEntry.SetRange("Source ID", PurchaseHeader."No.");
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        SurplusCountBefore := ReservationEntry.Count();
+
+        // [WHEN] Replan the item in the requisition worksheet
+        // Since Planning Flexibility is set to None, nothing should get planned
+        CalculatePlanForRequisitionWorksheet(Item);
+
+        // [THEN] Verify that no new surplus entries were created
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type"::Order.AsInteger());
+        ReservationEntry.SetRange("Source ID", PurchaseHeader."No.");
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        SurplusCountAfter := ReservationEntry.Count();
+
+        Assert.AreEqual(SurplusCountBefore, SurplusCountAfter,
+            'Number of Surplus reservation entries should not change after replanning when Planning Flexibility is None');
+
+        // [THEN] Verify that no Prospect entries remain for the Purchase Line
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Prospect);
+        ProspectCountAfter := ReservationEntry.Count();
+
+        Assert.AreEqual(0, ProspectCountAfter,
+            'No Prospect reservation entries should exist for the Purchase Line after the fix');
+    end;
+
+    [Test]
+    [HandlerFunctions('ItemTrackingLinesAssignLotNoPageHandler')]
+    [Scope('OnPrem')]
+    procedure TransferReservationsFromProspectToSurplusForPurchaseLine()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        PurchaseLine: Record "Purchase Line";
+        RequisitionLine: Record "Requisition Line";
+        ReservationEntry: Record "Reservation Entry";
+        Vendor: Record Vendor;
+        SalesQty: Decimal;
+        PurchQty: Decimal;
+        SurplusQtyTotal: Decimal;
+    begin
+        // [SCENARIO] When carrying out action message from requisition worksheet with item tracking,
+        // the reservation entries transferred to Purchase Line should have Surplus status (not Prospect)
+        // for the quantity exceeding the tracked demand.
+
+        // [GIVEN] Create an item with Lot-for-Lot reordering policy, Purchase replenishment and Lot tracking
+        Initialize();
+        SalesQty := 100;
+        PurchQty := 150;
+
+        CreateItemWithLotTrackingAndLotForLotPolicy(Item);
+        LibraryPurchase.CreateVendor(Vendor);
+
+        // [GIVEN] Create a Sales Order for 100 PCS
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", SalesQty);
+
+        // [GIVEN] Plan and modify the requisition line with increased quantity and Planning Flexibility = None
+        CalculatePlanForRequisitionWorksheet(Item);
+        FindRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate("Vendor No.", Vendor."No.");
+        RequisitionLine.Validate(Quantity, PurchQty);
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Modify(true);
+
+        // [GIVEN] Assign Lot No. tracking
+        RequisitionLine.OpenItemTrackingLines();
+
+        // [WHEN] Carry out action message
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        // [THEN] Find the created Purchase Line
+        PurchaseLine.SetRange(Type, PurchaseLine.Type::Item);
+        PurchaseLine.SetRange("No.", Item."No.");
+        PurchaseLine.SetRange("Document Type", PurchaseLine."Document Type"::Order);
+        PurchaseLine.FindFirst();
+
+        // [THEN] Verify that all surplus quantity (50 = 150 - 100) is in Surplus status
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type"::Order.AsInteger());
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+
+        SurplusQtyTotal := 0;
+        if ReservationEntry.FindSet() then
+            repeat
+                SurplusQtyTotal += ReservationEntry."Quantity (Base)";
+            until ReservationEntry.Next() = 0;
+
+        Assert.AreEqual(PurchQty - SalesQty, SurplusQtyTotal,
+            'Surplus quantity should equal the difference between purchase and sales quantity');
+
+        // [THEN] Verify no Prospect entries exist for the Purchase Line
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Prospect);
+        Assert.RecordIsEmpty(ReservationEntry);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Reservation Replanning Fix");
+        LibraryVariableStorage.Clear();
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Reservation Replanning Fix");
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Reservation Replanning Fix");
+    end;
+
+    local procedure CreateItemWithLotTrackingAndLotForLotPolicy(var Item: Record Item)
+    var
+        ItemTrackingCode: Record "Item Tracking Code";
+    begin
+        // Create Item Tracking Code with Lot Specific Tracking
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);
+
+        // Create Item with Lot-for-Lot reordering policy and Purchase replenishment
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        Item.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        Item.Validate("Replenishment System", Item."Replenishment System"::Purchase);
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::"Lot-for-Lot");
+        Item.Modify(true);
+    end;
+
+    local procedure CalculatePlanForRequisitionWorksheet(var Item: Record Item)
+    var
+        ReqWkshTemplate: Record "Req. Wksh. Template";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+    begin
+        SelectRequisitionTemplate(ReqWkshTemplate, ReqWkshTemplate.Type::"Req.");
+        LibraryPlanning.CreateRequisitionWkshName(RequisitionWkshName, ReqWkshTemplate.Name);
+        LibraryPlanning.CalculatePlanForReqWksh(
+            Item, ReqWkshTemplate.Name, RequisitionWkshName.Name, WorkDate(), CalcDate('<+1M>', WorkDate()));
+    end;
+
+    local procedure SelectRequisitionTemplate(var ReqWkshTemplate: Record "Req. Wksh. Template"; Type: Enum "Req. Worksheet Template Type")
+    begin
+        ReqWkshTemplate.SetRange(Type, Type);
+        ReqWkshTemplate.SetRange(Recurring, false);
+        ReqWkshTemplate.FindFirst();
+    end;
+
+    local procedure FindRequisitionLine(var RequisitionLine: Record "Requisition Line"; ItemNo: Code[20])
+    begin
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", ItemNo);
+        RequisitionLine.FindFirst();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ItemTrackingLinesAssignLotNoPageHandler(var ItemTrackingLines: TestPage "Item Tracking Lines")
+    begin
+        ItemTrackingLines."Assign Lot No.".Invoke();
+        ItemTrackingLines.OK().Invoke();
+    end;
+}

