+
+    [Test]
+    [Scope('OnPrem')]
+    procedure SalesReturnOrderItemChargeWithDefaultQtyToShipBlank()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesLineItemCharge: Record "Sales Line";
+        SalesReturnHeader: Record "Sales Header";
+        SalesReturnLine: Record "Sales Line";
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+        ItemChargeAssignmentSales: Record "Item Charge Assignment (Sales)";
+        SalesInvoiceLine: Record "Sales Invoice Line";
+        CopyDocMgt: Codeunit "Copy Document Mgt.";
+        CustomerNo: Code[20];
+        ItemNo: Code[20];
+        ItemChargeNo: Code[20];
+        Qty: Decimal;
+        LinesNotCopied: Integer;
+        MissingExCostRevLink: Boolean;
+    begin
+        // [FEATURE] [Sales] [Return Order] [Item Charge] [Default Quantity to Ship]
+        // [SCENARIO] Item Charge can be brought into Sales Return Order when Default Qty. to Ship is set to 'Blank'
+        Initialize();
+
+        // [GIVEN] "Default Quantity to Ship" is "Blank" in Sales & Receivables Setup
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Default Quantity to Ship", SalesReceivablesSetup."Default Quantity to Ship"::Blank);
+        SalesReceivablesSetup.Modify(true);
