+    begin
+        // [FEATURE] [Finance Charge Memo] [Multiple Posting Groups]
+        // [SCENARIO 537500] When issuing a Finance Charge Memo with an alternative Customer Posting Group,
+        // the G/L Entry should use the Receivables Account from the alternative posting group, not the original.
+        Initialize();
+
+        // [GIVEN] Allow Multiple Posting Groups is enabled in Sales & Receivables Setup.
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup."Allow Multiple Posting Groups" := true;
+        SalesReceivablesSetup."Check Multiple Posting Groups" := "Posting Group Change Method"::"Alternative Groups";
+        SalesReceivablesSetup.Modify();
+
+        // [GIVEN] A customer with Allow Multiple Posting Groups enabled.
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("Allow Multiple Posting Groups", true);
+        Customer.Modify();
+        CustomerPostingGroup.Get(Customer."Customer Posting Group");
+
+        // [GIVEN] An alternative Customer Posting Group with a different Receivables Account.
+        LibrarySales.CreateCustomerPostingGroup(AltCustomerPostingGroup);
+        LibrarySales.CreateAltCustomerPostingGroup(CustomerPostingGroup.Code, AltCustomerPostingGroup.Code);
+
+        // [GIVEN] A Finance Charge Memo for the customer with the alternative Customer Posting Group.
+        LibraryERM.CreateFinanceChargeTerms(FinanceChargeTerms);
+        FinanceChargeTerms.Validate("Post Interest", true);
+        FinanceChargeTerms.Modify(true);
+        LibraryERM.CreateFinanceChargeMemoHeader(FinanceChargeMemoHeader, Customer."No.");
+        FinanceChargeMemoHeader.Validate("Fin. Charge Terms Code", FinanceChargeTerms.Code);
+        FinanceChargeMemoHeader.Validate("Customer Posting Group", AltCustomerPostingGroup.Code);
+        FinanceChargeMemoHeader.Modify(true);
+        LibraryERM.CreateFinanceChargeMemoLine(
+          FinanceChargeMemoLine, FinanceChargeMemoHeader."No.", FinanceChargeMemoLine.Type::"Customer Ledger Entry");
+        FinanceChargeMemoLine.Validate(Amount, LibraryRandom.RandDecInRange(100, 1000, 2));
+        FinanceChargeMemoLine.Modify(true);
+
+        // [WHEN] The Finance Charge Memo is issued.
+        IssuedFinChargeMemoHeaderNo := IssuingFinanceChargeMemos(FinanceChargeMemoHeader."No.");
+
+        // [THEN] The Issued Finance Charge Memo Header has the alternative Customer Posting Group.
+        IssuedFinChargeMemoHeader.Get(IssuedFinChargeMemoHeaderNo);
+        Assert.AreEqual(
+            AltCustomerPostingGroup.Code, IssuedFinChargeMemoHeader."Customer Posting Group",
+            'Issued Fin. Charge Memo Header should have the alternative Customer Posting Group.');
+
+        // [THEN] The Customer Ledger Entry has the alternative Customer Posting Group.
