+    [Test]
+    [HandlerFunctions('MessageHandler,WhseSourceCreateDocumentOKHandler')]
+    procedure ChangeQtyOnLastTakeLineUpdatesCorrectPlaceLine()
+    var
+        Location: Record Location;
+        ParentItem: Record Item;
+        ComponentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder: Record "Production Order";
+        Bin: array[5] of Record Bin;
+        WarehouseEmployee: Record "Warehouse Employee";
+        ItemJournalLine: Record "Item Journal Line";
+        TakeLine: Record "Warehouse Activity Line";
+        PlaceLine: Record "Warehouse Activity Line";
+        i: Integer;
+        Qty: Decimal;
+        NewQty: Decimal;
+        TotalQty: Decimal;
+    begin
+        // [FEATURE] [Warehouse] [Pick] [Production Order]
+        // [SCENARIO] Changing quantity on last Take line should update the corresponding Place line, not the first Place line
+        Initialize();
+
+        // [GIVEN] Location with Require Pick and Prod. Consump. Whse. Handling = Warehouse Pick (mandatory)
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+        Location.Validate("Bin Mandatory", true);
+        Location.Validate("Require Pick", true);
+        Location.Validate("Prod. Consump. Whse. Handling", "Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)");
+        Location.Modify(true);
+
+        // [GIVEN] Create 5 Bins
+        for i := 1 to 5 do
+            LibraryWarehouse.CreateBin(Bin[i], Location.Code, 'BIN-' + Format(i), '', '');
+
+        // [GIVEN] Assign production bins to the location
+        Location.Validate("To-Production Bin Code", Bin[1].Code);
+        Location.Validate("From-Production Bin Code", Bin[2].Code);
+        Location.Modify(true);
+
+        // [GIVEN] Warehouse employee for location
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, false);
+
+        // [GIVEN] Component item with Allow Whse. Overpick = true
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Allow Whse. Overpick", true);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Parent item with production BOM containing component
+        LibraryInventory.CreateItem(ParentItem);
+        TotalQty := LibraryRandom.RandIntInRange(500, 600);
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, ComponentItem."No.", 1);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Post inventory for component item in multiple bins (Bin 3, 4, 5) with equal quantities
+        Qty := TotalQty / 3;
+        for i := 3 to 5 do begin
+            LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, ComponentItem."No.", Location.Code, Bin[i].Code, Qty);
+            LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+        end;
+
+        // [GIVEN] Create and refresh released production order
+        CreateAndRefreshProdOrder(ProductionOrder, ProductionOrder."Source Type"::Item, ParentItem."No.", Location.Code, TotalQty);
+
+        // [GIVEN] Create warehouse pick from production order - this creates Take/Place line pairs for each bin
+        ProductionOrder.CreatePick(UserId, 0, false, false, false);
+
+        // [GIVEN] Find all Take lines sorted by line number
+        TakeLine.SetRange("Activity Type", TakeLine."Activity Type"::Pick);
+        TakeLine.SetRange("Source Document", TakeLine."Source Document"::"Prod. Consumption");
+        TakeLine.SetRange("Source No.", ProductionOrder."No.");
+        TakeLine.SetRange("Action Type", TakeLine."Action Type"::Take);
+        TakeLine.SetRange("Item No.", ComponentItem."No.");
+        TakeLine.SetCurrentKey("Activity Type", "No.", "Line No.");
+        Assert.IsTrue(TakeLine.Count >= 2, 'Expected at least 2 Take lines to test the fix');
+
+        // [GIVEN] Find the last Take line and its corresponding Place line (with higher line no.)
+        TakeLine.FindLast();
+        NewQty := Round(Qty / 2, 1);
+
+        // [WHEN] Change quantity on the last Take line
+        TakeLine.Validate(Quantity, NewQty);
+        TakeLine.Modify(true);
+
+        // [THEN] The corresponding Place line (immediately after the last Take line) should be updated
+        PlaceLine.SetRange("Activity Type", PlaceLine."Activity Type"::Pick);
+        PlaceLine.SetRange("No.", TakeLine."No.");
+        PlaceLine.SetRange("Action Type", PlaceLine."Action Type"::Place);
+        PlaceLine.SetRange("Item No.", ComponentItem."No.");
+        PlaceLine.SetFilter("Line No.", '>%1', TakeLine."Line No.");
+        PlaceLine.FindFirst();
+
+        Assert.AreEqual(NewQty, PlaceLine.Quantity,
+            'The Place line immediately following the last Take line should have the updated quantity');
+
+        // [THEN] Verify the first Place line still has original quantity (was not incorrectly updated)
+        PlaceLine.Reset();
+        PlaceLine.SetRange("Activity Type", PlaceLine."Activity Type"::Pick);
+        PlaceLine.SetRange("No.", TakeLine."No.");
+        PlaceLine.SetRange("Action Type", PlaceLine."Action Type"::Place);
+        PlaceLine.SetRange("Item No.", ComponentItem."No.");
+        PlaceLine.SetRange(Quantity, Qty);
+        Assert.IsTrue(PlaceLine.Count >= 1,
+            'First Place lines should still have the original quantity');
+    end;
+
     local procedure Initialize()
     var
         WarehouseActivityLine: Record "Warehouse Activity Line";

