+codeunit 139614 "Shpfy Copy Document Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryAssert: Codeunit "Library Assert";
+        IsInitialized: Boolean;
+
+    local procedure Initialize()
+    begin
+        if IsInitialized then
+            exit;
+
+        Codeunit.Run(Codeunit::"Shpfy Initialize Test");
+        LibraryRandom.Init();
+        IsInitialized := true;
+        Commit();
+    end;
+
+    [Test]
+    procedure CopyPostedInvoiceClearsShopifyFields()
+    var
+        Customer: Record Customer;
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        ToSalesHeader: Record "Sales Header";
+        CopyDocumentMgt: Codeunit "Copy Document Mgt.";
+        ShpfyInitializeTest: Codeunit "Shpfy Initialize Test";
+        PostedInvoiceNo: Code[20];
+        ShopifyOrderId: BigInteger;
+        ShopifyOrderNo: Code[50];
+        ShopifyRefundId: BigInteger;
+    begin
+        // [SCENARIO] When copying a posted sales invoice with Shopify fields, the Shopify Order Id, Order No., and Refund Id should be cleared on the new sales document.
+        Initialize();
+
+        // [GIVEN] A posted sales invoice with Shopify Order Id, Order No., and Refund Id
+        ShpfyInitializeTest := ShpfyInitializeTest;
+        Customer := ShpfyInitializeTest.GetDummyCustomer();
+        Item := ShpfyInitializeTest.GetDummyItem();
+
+        LibrarySales.CreateSalesInvoiceForCustomerNo(SalesHeader, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", 1);
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDecInRange(10, 100, 2));
+        SalesLine.Modify(true);
+
+        // Set Shopify fields on the Sales Header before posting
+        ShopifyOrderId := LibraryRandom.RandIntInRange(1000000, 9999999);
+        ShopifyOrderNo := CopyStr(LibraryRandom.RandText(20), 1, MaxStrLen(ShopifyOrderNo));
+        ShopifyRefundId := LibraryRandom.RandIntInRange(1000000, 9999999);
+
+        SalesHeader."Shpfy Order Id" := ShopifyOrderId;
+        SalesHeader."Shpfy Order No." := ShopifyOrderNo;
+        SalesHeader."Shpfy Refund Id" := ShopifyRefundId;
+        SalesHeader.Modify();
+
+        // Post the invoice
+        PostedInvoiceNo := LibrarySales.PostSalesDocument(SalesHeader, false, true);
+
+        // Verify the posted invoice has Shopify fields
+        SalesInvoiceHeader.Get(PostedInvoiceNo);
+        LibraryAssert.AreEqual(ShopifyOrderId, SalesInvoiceHeader."Shpfy Order Id", 'Posted invoice should have Shopify Order Id');
+        LibraryAssert.AreEqual(ShopifyOrderNo, SalesInvoiceHeader."Shpfy Order No.", 'Posted invoice should have Shopify Order No.');
+
+        // [WHEN] Create a new sales invoice by copying from the posted invoice
+        LibrarySales.CreateSalesHeader(ToSalesHeader, ToSalesHeader."Document Type"::Invoice, Customer."No.");
+        CopyDocumentMgt.SetProperties(true, false, false, false, false, false, false);
+        CopyDocumentMgt.CopySalesDoc("Sales Document Type From"::"Posted Invoice", PostedInvoiceNo, ToSalesHeader);
+
+        // [THEN] The new sales header should have cleared Shopify fields
+        ToSalesHeader.Get(ToSalesHeader."Document Type", ToSalesHeader."No.");
+        LibraryAssert.AreEqual(0, ToSalesHeader."Shpfy Order Id", 'Copied sales header should have Shpfy Order Id cleared');
+        LibraryAssert.AreEqual('', ToSalesHeader."Shpfy Order No.", 'Copied sales header should have Shpfy Order No. cleared');
+        LibraryAssert.AreEqual(0, ToSalesHeader."Shpfy Refund Id", 'Copied sales header should have Shpfy Refund Id cleared');
+    end;
+}

