+        LibraryManufacturing.CreateRoutingHeader(RoutingHeader, RoutingHeader.Type::Serial);
+        LibraryManufacturing.CreateRoutingLine(
+            RoutingHeader,
+            RoutingLine,
+            '',
+            Format(1),
+            RoutingLine.Type::"Work Center",
+            WorkCenter."No.");
+        RoutingLine.Validate("Setup Time", LibraryRandom.RandDecInRange(5, 10, 0));
+        RoutingLine.Validate("Run Time", LibraryRandom.RandDecInRange(1, 5, 0));
+        RoutingLine.Modify(true);
+        LibraryManufacturing.UpdateRoutingStatus(RoutingHeader, RoutingHeader.Status::Certified);
+
+        // [GIVEN] Create Component Item with Standard Costing, Replenishment System = Prod. Order.
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Base Unit of Measure", PCSLbl);
+        ComponentItem.Validate("Costing Method", ComponentItem."Costing Method"::Standard);
+        ComponentItem.Validate("Standard Cost", LibraryRandom.RandDecInRange(10, 20, 2));
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::"Prod. Order");
+        ComponentItem.Validate("Routing No.", RoutingHeader."No.");
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Create Parent Item with Standard Costing, Replenishment System = Prod. Order.
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Base Unit of Measure", PCSLbl);
+        ParentItem.Validate("Costing Method", ParentItem."Costing Method"::Standard);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Create a blank Production BOM for the Component Item (no lines) and certify.
+        LibraryManufacturing.CreateProductionBOMHeader(BlankProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.UpdateProductionBOMStatus(BlankProductionBOMHeader, BlankProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Create Production BOM for Parent Item with Component Item as a line, Qty per > 1.
+        QtyPerBOMLine := LibraryRandom.RandIntInRange(2, 5);
+        LibraryManufacturing.CreateProductionBOMHeader(ParentProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ParentProductionBOMHeader,
+            ParentProductionBOMLine,
+            '',
+            ParentProductionBOMLine.Type::Item,
+            ComponentItem."No.",
+            QtyPerBOMLine);
+        LibraryManufacturing.UpdateProductionBOMStatus(ParentProductionBOMHeader, ParentProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Assign Production BOM to Parent Item.
+        ParentItem.Find();
+        ParentItem.Validate("Production BOM No.", ParentProductionBOMHeader."No.");
+        ParentItem.Modify(true);
