+        // [GIVEN] Clear Production BOM from Component Item (no BOM assigned).
+        ComponentItem.Find();
+        ComponentItem.Validate("Production BOM No.", '');
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Run 'Calc. Production BOM' action again from Parent Item.
+        Clear(CalculateStdCost);
+        CalculateStdCost.CalcItem(ParentItem."No.", false);
+
+        // [WHEN] Open 'Cost Shares' page for Parent Item and get Rolled-up Capacity Cost for Component.
