+        RunBOMCostSharesPage(ParentItem);
+        BOMCostShares.Expand(true);
+        BOMCostShares.FILTER.SetFilter(Type, Format(BOMBuffer.Type::Item));
+        BOMCostShares.FILTER.SetFilter("No.", ComponentItem."No.");
+        Evaluate(RolledUpCapacityWithNoBOM, Format(BOMCostShares."Rolled-up Capacity Cost"));
