+
+        // [THEN] Rolled-up Capacity Cost should be the same for both scenarios (blank BOM = no BOM).
+        Assert.AreEqual(RolledUpCapacityWithBlankBOM, RolledUpCapacityWithNoBOM, RolledUpCapacityDoNotMatchErr);
