+        // [GIVEN] Item with Base Unit of Measure = "PCS" and alternate Unit of Measure = "BOX"
+        // [GIVEN] Put-away Unit of Measure Code in the item is base unit (PCS)
+        // This setup will cause breakbulk lines when receiving in BOX UOM
+        LibraryInventory.CreateItem(Item);
