+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityHeader.Type);
+        WarehouseActivityLine.SetRange("No.", WarehouseActivityHeader."No.");
+        TotalPutAwayLinesBeforeRegister := WarehouseActivityLine.Count;
