+    [Test]
+    [Scope('OnPrem')]
+    procedure ProdOrderComponentQtyPerWithPartialQtyAndUOMRoundingPrecision()
+    var
+        ComponentItem: Record Item;
+        ParentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        QuantityPer: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Component] [Rounding Precision]
+        // [SCENARIO] When creating a Production Order for an item with a component whose Item UOM has 
+        // 'Qty. Rounding Precision' = 1, and the BOM uses a partial Quantity Per (like 0.09), 
+        // the component should use Item's Rounding Precision instead of UOM's Qty. Rounding Precision.
+        Initialize();
+        QuantityPer := 0.09;
+
+        // [GIVEN] Component item with Replenishment System = Purchase and Rounding Precision = 0.01
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Component Item's base UOM has 'Qty. Rounding Precision' = 1
+        ItemUnitOfMeasure.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] Production BOM with component item and Quantity Per = 0.09 (partial quantity)
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QuantityPer);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] Parent item (Finished Good) with Replenishment System = Prod. Order
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [WHEN] Create and refresh a Released Production Order for 1 qty of Parent Item
+        LibraryManufacturing.CreateProductionOrder(
+          ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, ParentItem."No.", 1);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [THEN] Prod Order Component has Quantity per = 0.09 (not rounded to 0 by UOM Qty. Rounding Precision)
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+        Assert.AreEqual(QuantityPer, ProdOrderComponent."Quantity per", 'Quantity per should equal the BOM Quantity Per');
+        Assert.AreEqual(QuantityPer, ProdOrderComponent."Expected Quantity", 'Expected Quantity should equal Quantity Per for 1 parent qty');
+    end;
 }

