+        // [GIVEN] Two Customer Posting Groups with different Receivables Accounts.
+        LibrarySales.CreateCustomerPostingGroup(CustomerPostingGroup[1]);
+        LibrarySales.CreateCustomerPostingGroup(CustomerPostingGroup[2]);
