+        // [GIVEN] Alternative Customer Posting Group is set up.
+        LibrarySales.CreateAltCustomerPostingGroup(CustomerPostingGroup[1].Code, CustomerPostingGroup[2].Code);
+
+        // [GIVEN] Customer with Allow Multiple Posting Groups enabled and primary posting group = CustomerPostingGroup[1].
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("Allow Multiple Posting Groups", true);
+        Customer.Validate("Customer Posting Group", CustomerPostingGroup[1].Code);
+        Customer.Modify(true);
+
+        // [GIVEN] Two journal entries posted for the same customer with different posting groups.
+        Amount1 := LibraryRandom.RandDecInRange(100, 200, 2);
+        Amount2 := LibraryRandom.RandDecInRange(300, 400, 2);
+
+        // Post first entry with CustomerPostingGroup[1]
+        LibraryERM.SelectGenJnlBatch(GenJournalBatch);
+        LibraryERM.ClearGenJournalLines(GenJournalBatch);
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::Invoice, GenJournalLine."Account Type"::Customer, Customer."No.", Amount1);
+        GenJournalLine.Validate("Posting Group", CustomerPostingGroup[1].Code);
+        GenJournalLine.Modify(true);
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // Post second entry with CustomerPostingGroup[2]
+        LibraryERM.ClearGenJournalLines(GenJournalBatch);
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::Invoice, GenJournalLine."Account Type"::Customer, Customer."No.", Amount2);
+        GenJournalLine.Validate("Posting Group", CustomerPostingGroup[2].Code);
+        GenJournalLine.Modify(true);
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [WHEN] Run the Reconcile Cust. and Vend. Accs Report for the Receivables Account of CustomerPostingGroup[1].
+        Clear(ReconcileCustAndVendAccs);
+        GLAccount.SetRange("No.", CustomerPostingGroup[1]."Receivables Account");
+        GLAccount.SetRange("Date Filter", WorkDate());
+        GLAccount.FindFirst();
+        ReconcileCustAndVendAccs.SetTableView(GLAccount);
+        Commit();
+        ReconcileCustAndVendAccs.Run();
+
+        // [THEN] The report shows Amount1 for CustomerPostingGroup[1] (entry-level amount, not the sum of both entries).
+        LibraryReportDataset.LoadDataSetFile();
+        LibraryReportDataset.SetRange('ReconCustVendBufferPostingGroup', CustomerPostingGroup[1].Code);
+        Assert.IsTrue(LibraryReportDataset.GetNextRow(), 'Expected row for CustomerPostingGroup[1] not found.');
+        LibraryReportDataset.AssertCurrentRowValueEquals('Amount', Amount1);
+
+        // [WHEN] Run the Reconcile Cust. and Vend. Accs Report for the Receivables Account of CustomerPostingGroup[2].
+        Clear(ReconcileCustAndVendAccs);
+        GLAccount.SetRange("No.", CustomerPostingGroup[2]."Receivables Account");
+        GLAccount.SetRange("Date Filter", WorkDate());
+        GLAccount.FindFirst();
+        ReconcileCustAndVendAccs.SetTableView(GLAccount);
+        Commit();
+        ReconcileCustAndVendAccs.Run();
