+        // [THEN] The report shows Amount2 for CustomerPostingGroup[2] (entry-level amount).
+        LibraryReportDataset.LoadDataSetFile();
+        LibraryReportDataset.SetRange('ReconCustVendBufferPostingGroup', CustomerPostingGroup[2].Code);
+        Assert.IsTrue(LibraryReportDataset.GetNextRow(), 'Expected row for CustomerPostingGroup[2] not found.');
+        LibraryReportDataset.AssertCurrentRowValueEquals('Amount', Amount2);
+    end;
 }

