+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PostGenJournalWithCurrencyAndLCYRoundingIssue()
+    var
+        AutomaticAccountHeader: Record "Automatic Account Header";
+        AutomaticAccountLine: Record "Automatic Account Line";
+        GenJournalLine: Record "Gen. Journal Line";
+        GenJournalLine2: Record "Gen. Journal Line";
+        GLEntry: Record "G/L Entry";
+        Currency: Record Currency;
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+        GLSetup: Record "General Ledger Setup";
+        GLAccountNo1: Code[20];
+        GLAccountNo2: Code[20];
+        GLAccountNo3: Code[20];
+        GLAccountNoMain: Code[20];
+        GLAccountNoBalance: Code[20];
+        AutoAccGroupNo: Code[10];
+        CurrencyCode: Code[10];
+        FCYAmount: Decimal;
+        LCYAmountExpected: Decimal;
+        DocumentNo: Code[20];
+        ExchRateAmount: Decimal;
+        RelationalExchRateAmount: Decimal;
+    begin
+        // [FEATURE] [Currency] [Rounding]
+        // [SCENARIO 562890] Post General Journal with Currency and Automatic Account Group where Amount (LCY) rounding causes inconsistency
+        // [GIVEN] Currency "EUR" with exchange rate that causes rounding issues (1 EUR = 10.97223 LCY)
+        // [GIVEN] Automatic Account Group "AAG" with three lines:
+        // [GIVEN]  Line1: "G/L Account No." = "ACC1", "Allocation %" = 50
+        // [GIVEN]  Line2: "G/L Account No." = "ACC2", "Allocation %" = 50
+        // [GIVEN]  Line3: "G/L Account No." = "ACC3", "Allocation %" = -100 (balancing line)
+        // [GIVEN] General Journal with Currency and two lines:
+        // [GIVEN] Line1: Amount = 480 EUR, "Automatic Account Group" = "AAG"
+        // [GIVEN] Line2: Amount = -480 EUR (balancing line, no AAG)
+        // [WHEN] Post General Journal
+        // [THEN] Posting succeeds without "Inconsistency" error
+        // [THEN] G/L Entries for the automatic account group are balanced correctly
+
+        Initialize();
+
+        // Setup currency with exchange rate that causes rounding issues
+        // 480 EUR * 10.97223 = 5266.6704 LCY -> rounds to 5266.67
+        // 5266.67 / 2 = 2633.335 -> rounds to 2633.34
+        // 2633.34 * 2 = 5266.68 <> 5266.67 (rounding issue)
+        GLSetup.Get();
+        CurrencyCode := LibraryERM.CreateCurrencyWithRandomExchRates();
+        Currency.Get(CurrencyCode);
+        Currency.Validate("Amount Rounding Precision", 0.01);
+        Currency.Modify(true);
+
+        // Set specific exchange rate to cause rounding issue
+        ExchRateAmount := 1;
+        RelationalExchRateAmount := 10.97223;
+        CurrencyExchangeRate.SetRange("Currency Code", CurrencyCode);
+        CurrencyExchangeRate.FindFirst();
+        CurrencyExchangeRate.Validate("Exchange Rate Amount", ExchRateAmount);
+        CurrencyExchangeRate.Validate("Adjustment Exch. Rate Amount", ExchRateAmount);
+        CurrencyExchangeRate.Validate("Relational Exch. Rate Amount", RelationalExchRateAmount);
+        CurrencyExchangeRate.Validate("Relational Adjmt Exch Rate Amt", RelationalExchRateAmount);
+        CurrencyExchangeRate.Modify(true);
+
+        // Create G/L Accounts for automatic account group
+        GLAccountNo1 := LibraryERM.CreateGLAccountNo();
+        GLAccountNo2 := LibraryERM.CreateGLAccountNo();
+        GLAccountNo3 := LibraryERM.CreateGLAccountNo();
+        GLAccountNoMain := LibraryERM.CreateGLAccountNo();
+        GLAccountNoBalance := LibraryERM.CreateGLAccountNo();
+
+        // Create Automatic Account Group with 50%, 50%, -100% allocation
+        LibraryAAC.CreateAutomaticAccountHeader(AutomaticAccountHeader);
+        AutoAccGroupNo := AutomaticAccountHeader."No.";
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo1);
+        AutomaticAccountLine.Validate("Allocation %", 50);
+        AutomaticAccountLine.Modify(true);
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo2);
+        AutomaticAccountLine.Validate("Allocation %", 50);
+        AutomaticAccountLine.Modify(true);
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo3);
+        AutomaticAccountLine.Validate("Allocation %", -100);
+        AutomaticAccountLine.Modify(true);
+
+        // Create General Journal with currency
+        FCYAmount := 480;
+        LibraryJournals.CreateGenJournalLineWithBatch(
+            GenJournalLine, GenJournalLine."Document Type"::" ",
+            GenJournalLine."Account Type"::"G/L Account", GLAccountNoMain,
+            FCYAmount);
+        GenJournalLine.Validate("Currency Code", CurrencyCode);
+        GenJournalLine.Validate("Bal. Account No.", '');
+        GenJournalLine.Validate("Automatic Account Group", AutoAccGroupNo);
+        GenJournalLine.Modify(true);
+        DocumentNo := GenJournalLine."Document No.";
+
+        // Create balancing line
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine2, GenJournalLine."Journal Template Name", GenJournalLine."Journal Batch Name",
+            GenJournalLine2."Document Type"::" ", GenJournalLine2."Account Type"::"G/L Account",
+            GLAccountNoBalance, -FCYAmount);
+        GenJournalLine2.Validate("Document No.", DocumentNo);
+        GenJournalLine2.Validate("Currency Code", CurrencyCode);
+        GenJournalLine2.Modify(true);
+
+        // Calculate expected LCY amount
+        LCYAmountExpected := Round(FCYAmount * RelationalExchRateAmount, GLSetup."Amount Rounding Precision");
+
+        // Post General Journal - this should succeed with the fix
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // Verify G/L Entries for automatic account group are balanced
+        GLEntry.SetRange("Document No.", DocumentNo);
+        GLEntry.SetRange("G/L Account No.", GLAccountNo1);
+        GLEntry.CalcSums(Amount);
+        Assert.AreNearlyEqual(
+            Round(LCYAmountExpected * 50 / 100, GLSetup."Amount Rounding Precision"),
+            GLEntry.Amount,
+            GLSetup."Amount Rounding Precision",
+            'Incorrect Amount for first allocation line');
+
+        GLEntry.SetRange("G/L Account No.", GLAccountNo2);
+        GLEntry.CalcSums(Amount);
+        Assert.AreNearlyEqual(
+            Round(LCYAmountExpected * 50 / 100, GLSetup."Amount Rounding Precision"),
+            GLEntry.Amount,
+            GLSetup."Amount Rounding Precision",
+            'Incorrect Amount for second allocation line');
+
+        // Verify the total of all allocation entries is zero (balanced)
+        GLEntry.SetFilter("G/L Account No.", '%1|%2|%3', GLAccountNo1, GLAccountNo2, GLAccountNo3);
+        GLEntry.CalcSums(Amount);
+        Assert.AreEqual(0, GLEntry.Amount, 'Automatic account group entries should balance to zero');
+    end;
 }

