+        // [SCENARIO] When a component item's UOM has 'Qty. Rounding Precision' = 1 and the Production BOM has a fractional Quantity Per,
+        // the Production Order Component should respect the item's Rounding Precision for calculating Quantity Per.
+        Initialize();
+        QtyPer := 0.09;
+
+        // [GIVEN] Create a Component Item with Replenishment System = Purchase and Item UOM with "Qty. Rounding Precision" = 1
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Validate("Reordering Policy", ComponentItem."Reordering Policy"::"Lot-for-Lot");
+        ComponentItem.Modify(true);
+
+        ItemUnitOfMeasure.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] Create a Production BOM with Component Item, Quantity Per = 0.09
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Create a Finished Good Item with Replenishment System = Prod. Order, Reordering Policy = Order
+        LibraryInventory.CreateItem(FinishedGoodItem);
+        FinishedGoodItem.Validate("Base Unit of Measure", ComponentItem."Base Unit of Measure");
+        FinishedGoodItem.Validate("Replenishment System", FinishedGoodItem."Replenishment System"::"Prod. Order");
+        FinishedGoodItem.Validate("Manufacturing Policy", FinishedGoodItem."Manufacturing Policy"::"Make-to-Order");
+        FinishedGoodItem.Validate("Reordering Policy", FinishedGoodItem."Reordering Policy"::Order);
+        FinishedGoodItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedGoodItem.Validate("Rounding Precision", 1);
+        FinishedGoodItem.Modify(true);
+
+        // [GIVEN] Create a Sales Order for 1 qty of the Finished Good Item
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order, '', FinishedGoodItem."No.", 1, '', WorkDate());
+
+        // [WHEN] Create Released Production Order from Sales Order
+        LibraryManufacturing.CreateProductionOrderFromSalesOrder(
+            SalesHeader, "Production Order Status"::Released, "Create Production Order Type"::ItemOrder);
+
+        // [THEN] Find the Production Order and verify the Component's "Quantity per" equals 0.09 (not 0)
+        ProductionOrder.SetRange(Status, ProductionOrder.Status::Released);
+        ProductionOrder.SetRange("Source Type", ProductionOrder."Source Type"::Item);
+        ProductionOrder.SetRange("Source No.", FinishedGoodItem."No.");
+        ProductionOrder.FindFirst();
+
+        ProdOrderComponent.SetRange(Status, ProductionOrder.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+
+        // [THEN] Quantity Per and Expected Quantity should be 0.09, not 0
+        Assert.AreEqual(QtyPer, ProdOrderComponent."Quantity per", 'Quantity per on Prod. Order Component should match BOM Quantity Per');
+        Assert.AreEqual(QtyPer, ProdOrderComponent."Expected Quantity", 'Expected Quantity on Prod. Order Component should match BOM Quantity Per');
+    end;
