+codeunit 139614 "Shpfy Add Item To Shopify Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryAssert: Codeunit "Library Assert";
+
+    [Test]
+    procedure UnitTestAddItemWithEmptyDescriptionSkipped()
+    var
+        Item: Record Item;
+        Shop: Record "Shpfy Shop";
+        SkippedRecord: Record "Shpfy Skipped Record";
+        InitializeTest: Codeunit "Shpfy Initialize Test";
+        AddItemToShopify: Report "Shpfy Add Item to Shopify";
+        ItemDescriptionIsEmptyLbl: Label 'Item description is empty.';
+    begin
+        // [SCENARIO] When adding an item with empty description to Shopify, the item should be skipped and logged in Skipped entries.
+
+        // [GIVEN] A Shop
+        Shop := InitializeTest.CreateShop();
+        Shop."Logging Mode" := "Shpfy Logging Mode"::All;
+        Shop.Modify();
+
+        // [GIVEN] An item with empty description
+        Item := CreateItemWithEmptyDescription(Shop."Item Templ. Code");
+
+        // [GIVEN] Delete any existing skipped records for this item
+        SkippedRecord.SetRange("Record ID", Item.RecordId);
+        SkippedRecord.DeleteAll();
+
+        // [WHEN] Run the "Add Item to Shopify" report for this item
+        AddItemToShopify.SetShop(Shop.Code);
+        Item.SetRecFilter();
+        AddItemToShopify.SetTableView(Item);
+        AddItemToShopify.UseRequestPage(false);
+        AddItemToShopify.Run();
+
+        // [THEN] A skipped record should be created with the reason "Item description is empty."
+        SkippedRecord.Reset();
+        SkippedRecord.SetRange("Record ID", Item.RecordId);
+        SkippedRecord.SetRange("Skipped Reason", ItemDescriptionIsEmptyLbl);
+        LibraryAssert.IsTrue(SkippedRecord.FindFirst(), 'Item with empty description should be logged as skipped.');
+    end;
+
+    local procedure CreateItemWithEmptyDescription(TemplateCode: Code[20]) Item: Record Item
+    var
+        ItemTempl: Record "Item Templ.";
+        ItemTemplMgt: Codeunit "Item Templ. Mgt.";
+        Any: Codeunit Any;
+        IsHandled: Boolean;
+    begin
+        Any.SetDefaultSeed();
+        Item.Init();
+        Item."No." := Any.AlphabeticText(MaxStrLen(Item."No."));
+        Item.Insert(true);
+
+        if ItemTempl.Get(TemplateCode) then
+            ItemTemplMgt.ApplyItemTemplate(Item, ItemTempl);
+
+        // Explicitly set description to empty
+        Item.Description := '';
+        Item.Modify();
+    end;
+}

