diff --git a/App/Layers/W1/Tests/SCM/SCMInvDiscCurrencyExchRate.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMInvDiscCurrencyExchRate.Codeunit.al
new file mode 100644
index 00000000..02b78d9a
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMInvDiscCurrencyExchRate.Codeunit.al
@@ -0,0 +1,203 @@
+codeunit 137299 "SCM Inv. Disc. Currency Exch."
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Invoice Discount] [Currency] [Inventory Pick]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('MessageHandler,CreateInvtPickRequestPageHandler')]
+    [Scope('OnPrem')]
+    procedure InvoiceDiscountPreservedWhenCurrencyFactorChangesOnInvtPickPost()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        Location: Record Location;
+        Bin: Record Bin;
+        Item: Record Item;
+        Currency: Record Currency;
+        CustInvoiceDisc: Record "Cust. Invoice Disc.";
+        Customer: Record Customer;
+        ItemJournalLine: Record "Item Journal Line";
+        InitialPostingDate: Date;
+        NewPostingDate: Date;
+        InvoiceDiscountPct: Decimal;
+        UnitPrice: Decimal;
+        Quantity: Decimal;
+        InitialExchangeRate: Decimal;
+        NewExchangeRate: Decimal;
+        InvoiceDiscountAmountBefore: Decimal;
+    begin
+        // [SCENARIO] Invoice discount should be preserved when posting inventory pick with different posting date 
+        // that causes currency factor recalculation on a sales order
+        Initialize();
+
+        // [GIVEN] Location for Inventory Pick where 'Require Pick' and 'Bin Mandatory' are true
+        CreateLocationWMSWithWhseEmployee(Location, true, false, true, false, false);
+        LibraryWarehouse.CreateBin(
+            Bin, Location.Code,
+            CopyStr(
+                LibraryUtility.GenerateRandomCode(Bin.FieldNo(Code), DATABASE::Bin), 1,
+                LibraryUtility.GetFieldLength(DATABASE::Bin, Bin.FieldNo(Code))), '', '');
+        Location.Validate("Default Bin Code", Bin.Code);
+        Location.Modify(true);
+
+        // [GIVEN] Item with inventory at the location
+        LibraryInventory.CreateItem(Item);
+        Quantity := LibraryRandom.RandIntInRange(5, 20);
+        UnitPrice := LibraryRandom.RandDecInRange(100, 1000, 2);
+        LibraryInventory.CreateItemJournalLineInItemTemplate(
+            ItemJournalLine, Item."No.", Location.Code, Bin.Code, Quantity * 2);
+        LibraryInventory.PostItemJournalLine(
+            ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] Currency with different exchange rates on different dates
+        InitialPostingDate := WorkDate();
+        NewPostingDate := WorkDate() + 14;
+        InitialExchangeRate := LibraryRandom.RandDecInRange(1, 2, 2);
+        NewExchangeRate := LibraryRandom.RandDecInRange(3, 5, 2);
+
+        LibraryERM.CreateCurrency(Currency);
+        LibraryERM.CreateExchangeRate(Currency.Code, InitialPostingDate, InitialExchangeRate, InitialExchangeRate);
+        LibraryERM.CreateExchangeRate(Currency.Code, NewPostingDate, NewExchangeRate, NewExchangeRate);
+
+        // [GIVEN] Customer with invoice discount setup
+        InvoiceDiscountPct := LibraryRandom.RandDecInRange(5, 15, 2);
+        LibrarySales.CreateCustomer(Customer);
+        LibraryERM.CreateInvDiscForCustomer(CustInvoiceDisc, Customer."No.", Currency.Code, 0);
+        CustInvoiceDisc.Validate("Discount %", InvoiceDiscountPct);
+        CustInvoiceDisc.Modify(true);
+        Customer.Validate("Invoice Disc. Code", CustInvoiceDisc.Code);
+        Customer.Modify(true);
+
+        // [GIVEN] Sales order with FCY, at the location with bin, and invoice discount applied
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+        SalesHeader.Validate("Currency Code", Currency.Code);
+        SalesHeader.Validate("Location Code", Location.Code);
+        SalesHeader.Validate("Posting Date", InitialPostingDate);
+        SalesHeader.Modify(true);
+
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", Quantity);
+        SalesLine.Validate("Location Code", Location.Code);
+        SalesLine.Validate("Bin Code", Bin.Code);
+        SalesLine.Validate("Unit Price", UnitPrice);
+        SalesLine.Modify(true);
+
+        // Apply invoice discount
+        CalculateInvoiceDiscount(SalesLine);
+
+        // Verify invoice discount is applied
+        SalesLine.Get(SalesLine."Document Type", SalesLine."Document No.", SalesLine."Line No.");
+        Assert.AreNotEqual(0, SalesLine."Inv. Discount Amount", 'Invoice discount should be applied');
+        InvoiceDiscountAmountBefore := SalesLine."Inv. Discount Amount";
+
+        // [GIVEN] Inventory Pick created from the sales order
+        LibrarySales.ReleaseSalesDocument(SalesHeader);
+        Commit();
+        SalesHeader.CreateInvtPutAwayPick();
+
+        // [GIVEN] Inventory Pick posting date changed to date with different exchange rate
+        FindWarehouseActivityLine(
+            WarehouseActivityLine, DATABASE::"Sales Line", SalesHeader."No.",
+            WarehouseActivityLine."Activity Type"::"Invt. Pick");
+        WarehouseActivityHeader.Get(WarehouseActivityLine."Activity Type", WarehouseActivityLine."No.");
+        WarehouseActivityHeader.Validate("Posting Date", NewPostingDate);
+        WarehouseActivityHeader.Modify(true);
+        LibraryWarehouse.SetQtyToHandleWhseActivity(WarehouseActivityHeader, WarehouseActivityLine.Quantity);
+        Commit();
+
+        // [WHEN] Inventory Pick is posted (Ship)
+        LibraryWarehouse.PostInventoryActivity(WarehouseActivityHeader, false);
+
+        // [THEN] Invoice discount should be preserved on the sales line
+        SalesHeader.Get(SalesHeader."Document Type", SalesHeader."No.");
+        SalesLine.Get(SalesLine."Document Type", SalesLine."Document No.", SalesLine."Line No.");
+
+        // Verify posting date was updated
+        Assert.AreEqual(NewPostingDate, SalesHeader."Posting Date", 'Posting Date should be updated');
+
+        // Verify invoice discount is preserved (the key assertion for this fix)
+        Assert.AreNotEqual(0, SalesLine."Inv. Discount Amount", 'Invoice discount should be preserved after posting inventory pick with different posting date');
+        Assert.AreEqual(InvoiceDiscountAmountBefore, SalesLine."Inv. Discount Amount", 'Invoice discount amount should remain unchanged');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
