+          ProductionBOMHeader1, ProductionBOMLine, '', ProductionBOMLine.Type::Item, LowestItem."No.", 1);
+        ProductionBOMHeader1.Validate(Status, ProductionBOMHeader1.Status::Certified);
+        ProductionBOMHeader1.Modify(true);
+        MidItem1.Validate("Production BOM No.", ProductionBOMHeader1."No.");
+        MidItem1.Modify(true);
+
+        CreateAndUpdateItem(
+          MidItem2, MidItem2."Replenishment System"::"Prod. Order", MidItem2."Reordering Policy"::"Lot-for-Lot",
+          MidItem2."Manufacturing Policy"::"Make-to-Order", '');
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader2, MidItem2."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeader2, ProductionBOMLine, '', ProductionBOMLine.Type::Item, LowestItem."No.", 1);
+        ProductionBOMHeader2.Validate(Status, ProductionBOMHeader2.Status::Certified);
+        ProductionBOMHeader2.Modify(true);
+        MidItem2.Validate("Production BOM No.", ProductionBOMHeader2."No.");
+        MidItem2.Modify(true);
+
+        // [GIVEN] Create top-level item (Item1) with Make-to-Order, Lot-for-Lot, Prod. Order replenishment
+        // with MidItem1 and MidItem2 as components
+        CreateAndUpdateItem(
+          TopItem, TopItem."Replenishment System"::"Prod. Order", TopItem."Reordering Policy"::"Lot-for-Lot",
+          TopItem."Manufacturing Policy"::"Make-to-Order", '');
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeaderTop, TopItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeaderTop, ProductionBOMLine, '', ProductionBOMLine.Type::Item, MidItem1."No.", 1);
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeaderTop, ProductionBOMLine, '', ProductionBOMLine.Type::Item, MidItem2."No.", 1);
+        ProductionBOMHeaderTop.Validate(Status, ProductionBOMHeaderTop.Status::Certified);
+        ProductionBOMHeaderTop.Modify(true);
+        TopItem.Validate("Production BOM No.", ProductionBOMHeaderTop."No.");
+        TopItem.Modify(true);
+
+        // [GIVEN] Create a Released Production Order for TopItem with Quantity 1 and refresh it
+        // After refresh, LowestItem should have a Prod. Order Line with quantity 2 (1 for MidItem1 + 1 for MidItem2)
+        LibraryManufacturing.CreateProductionOrder(
