+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure UndoTransferShipmentAfterRevaluation()
+    var
+        Item: Record Item;
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        ValueEntry: Record "Value Entry";
+        FromLocation: Record Location;
+        ToLocation: Record Location;
+        OriginalUnitCost: Decimal;
+        RevaluedUnitCost: Decimal;
+        Qty: Decimal;
+        PositiveAdjmtEntryNo: Integer;
+    begin
+        // [FEATURE] [Transfer] [Order] [Undo Shipment] [Revaluation]
+        // [SCENARIO] Undo Transfer Shipment after revaluation of original item ledger entry should correctly value the correcting entry
+        Initialize();
+
+        // [GIVEN] Create an item with positive inventory at initial cost
+        OriginalUnitCost := LibraryRandom.RandIntInRange(10, 20);
+        RevaluedUnitCost := OriginalUnitCost + LibraryRandom.RandIntInRange(5, 10);
+        Qty := 1;
+
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(FromLocation);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(ToLocation);
+
+        LibraryInventory.CreateItem(Item);
+        CreateAndPostItemJnlWithCostLocationVariant(
+          ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", Qty, OriginalUnitCost, FromLocation.Code, '');
+
+        // Find the positive adjustment Item Ledger Entry
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::"Positive Adjmt.");
+        ItemLedgerEntry.FindFirst();
+        PositiveAdjmtEntryNo := ItemLedgerEntry."Entry No.";
+
+        // [GIVEN] Create and post transfer shipment (ship only)
+        CreateTransferOrderNoRoute(TransferHeader, TransferLine, FromLocation.Code, ToLocation.Code, Item."No.", '', Qty);
+        LibraryInventory.PostTransferHeader(TransferHeader, true, false);
+
+        // [GIVEN] Revalue the original positive adjustment item ledger entry
+        LibraryInventory.CreateItemJournalBatchByType(ItemJournalBatch, ItemJournalBatch."Template Type"::Revaluation);
+        LibraryInventory.MakeItemJournalLine(ItemJournalLine, ItemJournalBatch, Item, WorkDate(), ItemJournalLine."Entry Type"::Purchase, 0);
+        ItemJournalLine.Validate("Applies-to Entry", PositiveAdjmtEntryNo);
+        ItemJournalLine.Validate("Unit Cost (Revalued)", RevaluedUnitCost);
+        ItemJournalLine.Insert();
+        LibraryInventory.PostItemJournalBatch(ItemJournalBatch);
+
+        // [GIVEN] Run Adjust Cost - Item Entries
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [WHEN] Undo the transfer shipment
+        LibraryInventory.UndoTransferShipments(TransferHeader."No.");
+
+        // [WHEN] Run Adjust Cost - Item Entries again
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [THEN] The total cost amount of all transfer entries (shipment + correction) should be zero
+        ValueEntry.SetRange("Item No.", Item."No.");
+        ValueEntry.SetRange("Item Ledger Entry Type", ValueEntry."Item Ledger Entry Type"::Transfer);
+        ValueEntry.CalcSums("Cost Amount (Actual)");
+        Assert.AreEqual(0, ValueEntry."Cost Amount (Actual)", 'Total cost amount of transfer entries should be zero after undo');
+
+        // [THEN] The correcting transfer entry (positive qty, returning item to from-location) should have the revalued cost
+        ItemLedgerEntry.Reset();
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Transfer);
+        ItemLedgerEntry.SetRange("Location Code", FromLocation.Code);
+        ItemLedgerEntry.SetFilter(Quantity, '>0');
+        ItemLedgerEntry.FindFirst();
+        ItemLedgerEntry.CalcFields("Cost Amount (Actual)");
+        Assert.AreEqual(RevaluedUnitCost * Qty, ItemLedgerEntry."Cost Amount (Actual)", 'Correcting entry should have the revalued cost');
+    end;
+
     [Test]
     [HandlerFunctions('ConfirmHandlerYes')]
     [Scope('OnPrem')]

