+    [Test]
+    [Scope('OnPrem')]
+    procedure OpenJnlUsesRecordTemplateWhenTemplateIsSetAndNoBatchFilter()
+    var
+        ReqWkshTemplate1: Record "Req. Wksh. Template";
+        ReqWkshTemplate2: Record "Req. Wksh. Template";
+        ReqWkshName1: Record "Requisition Wksh. Name";
