+        ReqWkshName1.Description := 'Batch in Template 1';
+        ReqWkshName1.Insert(true);
+
+        ReqWkshName2.Init();
+        ReqWkshName2."Worksheet Template Name" := ReqWkshTemplate2.Name;
+        ReqWkshName2.Name := 'BATCH2';
+        ReqWkshName2.Description := 'Batch in Template 2';
+        ReqWkshName2.Insert(true);
